INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 1, 'PEDRO, apóstol de Jesucristo, á los extranjeros esparcidos en Ponto, en Galacia, en Capadocia, en Asia, y en Bithinia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 2, 'Elegidos según la presciencia de Dios Padre en santificación del Espíritu, para obedecer y ser rociados con la sangre de Jesucristo: Gracia y paz os sea multiplicada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 3, 'Bendito el Dios y Padre de nuestro Señor Jesucristo, que según su grande misericordia nos ha regenerado en esperanza viva, por la resurrección de Jesucristo de los muertos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 4, 'Para una herencia incorruptible, y que no puede contaminarse, ni marchitarse, reservada en los cielos');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 5, 'Para nosotros que somos guardados en la virtud de Dios por fe, para alcanzar la salud que está aparejada para ser manifestada en el postrimero tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 6, 'En lo cual vosotros os alegráis, estando al presente un poco de tiempo afligidos en diversas tentaciones, si es necesario,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 7, 'Para que la prueba de vuestra fe, mucho más preciosa que el oro, el cual perece, bien que sea probado con fuego, sea hallada en alabanza, gloria y honra, cuando Jesucristo fuera manifestado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 8, 'Al cual, no habiendo visto, le amáis; en el cual creyendo, aunque al presente no lo veáis, os alegráis con gozo inefable y glorificado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 9, 'Obteniendo el fin de vuestra fe, que es la salud de vuestras almas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 10, 'De la cual salud los profetas que profetizaron de la gracia que había de venir á vosotros, han inquirido y diligentemente buscado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 11, 'Escudriñando cuándo y en qué punto de tiempo significaba el Espíritu de Cristo que estaba en ellos, el cual prenunciaba las aflicciones que habían de venir á Cristo, y las glorias después de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 12, 'A los cuales fué revelado, que no para sí mismos, sino para nosotros administraban las cosas que ahora os son anunciadas de los que os han predicado el evangelio por el Espíritu Santo enviado del cielo; en las cuales desean mirar los ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 13, 'Por lo cual, teniendo los lomos de vuestro entendimiento ceñidos, con templanza, esperad perfectamente en la gracia que os es presentada cuando Jesucristo os es manifestado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 14, 'Como hijos obedientes, no conformándoos con los deseos que antes teníais estando en vuestra ignorancia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 15, 'Sino como aquel que os ha llamado es santo, sed también vosotros santos en toda conversación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 16, 'Porque escrito está: Sed santos, porque yo soy santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 17, 'Y si invocáis por Padre á aquel que sin acepción de personas juzga según la obra de cada uno, conversad en temor todo el tiempo de vuestra peregrinación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 18, 'Sabiendo que habéis sido rescatados de vuestra vana conversación, la cual recibisteis de vuestros padres, no con cosas corruptibles, como oro ó plata;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 19, 'Sino con la sangre preciosa de Cristo, como de un cordero sin mancha y sin contaminación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 20, 'Ya ordenado de antes de la fundación del mundo, pero manifestado en los postrimeros tiempos por amor de vosotros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 21, 'Que por él creéis á Dios, el cual le resucitó de los muertos, y le ha dado gloria, para que vuestra fe y esperanza sea en Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 22, 'Habiendo purificado vuestra almas en la obediencia de la verdad, por el Espíritu, en caridad hermanable sin fingimiento, amaos unos á otros entrañablemente de corazón puro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 23, 'Siendo renacidos, no de simiente corruptible, sino de incorruptible, por la palabra de Dios, que vive y permanece para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 24, 'Porque Toda carne es como la hierba, Y toda la gloria del hombre como la flor de la hierba: Secóse la hierba, y la flor se cayó;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 1, 25, 'Mas la palabra del Señor permanece perpetuamente. Y esta es la palabra que por el evangelio os ha sido anunciada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 1, 'DEJANDO pues toda malicia, y todo engaño, y fingimientos, y envidias, y todas las detracciones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 2, 'Desead, como niños recién nacidos, la leche espiritual, sin engaño, para que por ella crezcáis en salud:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 3, 'Si empero habéis gustado que el Señor es benigno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 4, 'Al cual allegándoos, piedra viva, reprobada cierto de los hombres, empero elegida de Dios, preciosa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 5, 'Vosotros también, como piedras vivas, sed edificados una casa espitirual, y un sacerdocio santo, para ofrecer sacrificios espirituales, agradables á Dios por Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 6, 'Por lo cual también contiene la Escritura: He aquí, pongo en Sión la principal piedra del ángulo, escogida, preciosa; Y el que creyere en ella, no será confundido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 7, 'Ella es pues honor á vosotros que creéis: mas para los desobedientes, La piedra que los edificadores reprobaron, Esta fué hecha la cabeza del ángulo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 8, 'Y Piedra de tropiezo, y roca de escándalo á aquellos que tropiezan en la palabra, siendo desobedientes; para lo cual fueron también ordenados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 9, 'Mas vosotros sois linaje escogido, real sacerdocio, gente santa, pueblo adquirido, para que anunciéis las virtudes de aquel que os ha llamado de las tinieblas á su luz admirable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 10, 'Vosotros, que en el tiempo pasado no erais pueblo, mas ahora sois pueblo de Dios; que en el tiempo pasado no habíais alcanzado misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 11, 'Amados, yo os ruego como á extranjeros y peregrinos, os abstengáis de los deseos carnales que batallan contra el alma,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 12, 'Teniendo vuestra conversación honesta entre los Gentiles; para que, en lo que ellos murmuran de vosotros como de malhechores, glorifiquen á Dios en el día de la visitación, estimándoos por las buenas obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 13, 'Sed pues sujetos á toda ordenación humana por respeto á Dios: ya sea al rey, como á superior,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 14, 'Ya á los gobernadores, como de él enviados para venganza de los malhechores, y para loor de los que hacen bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 15, 'Porque esta es la voluntad de Dios; que haciendo bien, hagáis callara la ignorancia de los hombres vanos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 16, 'Como libres, y no como teniendo la libertad por cobertura de malicia, sino como siervos de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 17, 'Honrad á todos. Amad la fraternidad. Temed á Dios. Honrad al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 18, 'Siervos, sed sujetos con todo temor á vuestros amos; no solamente á los buenos y humanos, sino también á los rigurosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 19, 'Porque esto es agradable, si alguno á causa de la conciencia delante de Dios, sufre molestias padeciendo injustamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 20, 'Porque ¿qué gloria es, si pecando vosotros sois abofeteados, y lo sufrís? mas si haciendo bien sois afligidos, y lo sufrís, esto ciertamente es agradable delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 21, 'Porque para esto sois llamados; pues que también Cristo padeció por nosotros, dejándonos ejemplo, para que vosotros sigáis sus pisadas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 22, 'El cual no hizo pecado; ni fué hallado engaño en su boca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 23, 'Quien cuando le maldecían no retornaba maldición: cuando padecía, no amenazaba, sino remitía la causa al que juzga justamente:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 24, 'El cual mismo llevó nuestros pecados en su cuerpo sobre el madero, para que nosotros siendo muertos á los pecados, vivamos á la justicia: por la herida del cual habéis sido sanados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 2, 25, 'Porque vosotros erais como ovejas descarriadas; mas ahora habéis vuelto al Padre y Obispo de vuestras almas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 1, 'ASIMISMO vosotras, mujeres, sed sujetas á vuestros maridos; para que también los que no creen á la palabra, sean ganados sin palabra por la conversación de sus mujeres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 2, 'Considerando vuestra casta conversación, que es en temor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 3, 'El adorno de las cuales no sea exterior con encrespamiento del cabello, y atavío de oro, ni en compostura de ropas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 4, 'Sino el hombre del corazón que está encubierto, en incorruptible ornato de espíritu agradable y pacífico, lo cual es de grande estima delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 5, 'Porque así también se ataviaban en el tiempo antiguo aquellas santas mujeres que esperaban en Dios, siendo sujetas á sus maridos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 6, 'Como Sara obedecía á Abraham, llamándole señor; de la cual vosotras sois hechas hijas, haciendo bien, y no sois espantadas de ningún pavor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 7, 'Vosotros maridos, semejantemente, habitad con ellas según ciencia, dando honor á la mujer como á vaso más frágil, y como á herederas juntamente de la gracia de la vida; para que vuestras oraciones no sean impedidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 8, 'Y finalmente, sed todos de un mismo corazón, compasivos, amándoos fraternalmente, misericordiosos, amigables;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 9, 'No volviendo mal por mal, ni maldición por maldición, sino antes por el contrario, bendiciendo; sabiendo que vosotros sois llamados para que poseáis bendición en herencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 10, 'Porque El que quiere amar la vida, Y ver días buenos, Refrene su lengua de mal, Y sus labios no hablen engaño;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 11, 'Apártase del mal, y haga bien; Busque la paz, y sígala.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 12, 'Porque los ojos del Señor están sobre los justos, Y sus oídos atentos á sus oraciones: Pero el rostro del Señor está sobre aquellos que hacen mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 13, '¿Y quién es aquel que os podrá dañar, si vosotros seguís el bien?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 14, 'Mas también si alguna cosa padecéis por hacer bien, sois bienaventurados. Por tanto, no temáis por el temor de ellos, ni seáis turbados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 15, 'Sino santificad al Señor Dios en vuestros corazones, y estad siempre aparejados para responder con masedumbre y reverencia á cada uno que os demande razón de la esperanza que hay en vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 16, 'Teniendo buena conciencia, para que en lo que murmuran de vosotros como de malhechores, sean confundidos los que blasfeman vuestra buena conversación en Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 17, 'Porque mejor es que padezcáis haciendo bien, si la voluntad de Dios así lo quiere, que haciendo mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 18, 'Porque también Cristo padeció una vez por los injustos, para llevarnos á Dios, siendo á la verdad muerto en la carne, pero vivificado en espíritu;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 19, 'En el cual también fué y predicó á los espíritus encarcelados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 20, 'Los cuales en otro tiempo fueron desobedientes, cuando una vez esperaba la paciencia de Dios en los días de Noé, cuando se aparejaba el arca; en la cual pocas, es á saber, ocho personas fueron salvas por agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 21, 'A la figura de la cual el bautismo que ahora corresponde nos salva (no quitando las inmundicias de la carne, sino como demanda de una buena conciencia delante de Dios,) por la resurrección de Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 3, 22, 'El cual está á la diestra de Dios, habiendo subido al cielo; estando á él sujetos los ángeles, y las potestades, y virtudes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 1, 'PUES que Cristo ha padecido por nosotros en la carne, vosotros también estad armados del mismo pensamiento: que el que ha padecido en la carne, cesó de pecado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 2, 'Para que ya el tiempo que queda en carne, viva, no á las concupiscencias de los hombres, sino á la voluntad de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 3, 'Porque nos debe bastar que el tiempo pasado de nuestra vida hayamos hecho la voluntad de los Gentiles, cuando conversábamos en lascivias, en concupiscencias, en embriagueces, abominables idolatrías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 4, 'En lo cual les parece cosa extraña que vosotros no corráis con ellos en el mismo desenfrenamiento de disolución, ultrajándoos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 5, 'Los cuales darán cuenta al que está aparejado para juzgar los vivos y los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 6, 'Porque por esto también ha sido predicado el evangelio á los muertos; para que sean juzgados en carne según los hombres, y vivan en espíritu según Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 7, 'Mas el fin de todas las cosas se acerca: sed pues templados, y velad en oración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 8, 'Y sobre todo, tened entre vosotros ferviente caridad; porque la caridad cubrirá multitud de pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 9, 'Hospedaos los unos á los otros sin murmuraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 10, 'Cada uno según el don que ha recibido, adminístrelo á los otros, como buenos dispensadores de las diferentes gracias de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 11, 'Si alguno habla, hable conforme á las palabras de Dios; si alguno ministra, ministre conforme á la virtud que Dios suministra: para que en todas cosas sea Dios glorificado por Jesucristo, al cual es gloria é imperio para siempre jamás. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 12, 'Carísimos, no os maravilléis cuando sois examinados por fuego, lo cual se hace para vuestra prueba, como si alguna cosa peregrina os aconteciese;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 13, 'Antes bien gozaos en que sois participantes de las aflicciones de Cristo; para que también en la revelación de su gloria os gocéis en triunfo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 14, 'Si sois vituperados en el nombre de Cristo, sois bienaventurados; porque la gloria y el Espíritu de Dios reposan sobre vosotros. Cierto, según ellos, él es blasfemado, mas según vosotros es glorificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 15, 'Así que, ninguno de vosotros padezca como homicida, ó ladrón, ó malhechor, ó por meterse en negocios ajenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 16, 'Pero si alguno padece como Cristiano, no se avergüence; antes glorifique á Dios en esta parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 17, 'Porque es tiempo de que el juicio comience de la casa de Dios: y si primero comienza por nosotros, ¿qué será el fin de aquellos que no obedecen al evangelio de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 18, 'Y si el justo con dificultad se salva; ¿á dónde aparecerá el infiel y el pecador?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 4, 19, 'Y por eso los que son afligidos según la voluntad de Dios, encomiéndenle sus almas, como á fiel Criador, haciendo bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 1, 'RUEGO á los ancianos que están entre vosotros, yo anciano también con ellos, y testigo de las afliciciones de Cristo, que soy también participante de la gloria que ha de ser revelada:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 2, 'Apacentad la grey de Dios que está entre vosotros, teniendo cuidado de ella, no por fuerza, sino voluntariamente; no por ganancia deshonesta, sino de un ánimo pronto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 3, 'Y no como teniendo señorío sobre las heredades del Señor, sino siendo dechados de la grey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 4, 'Y cuando apareciere el Príncipe de los pastores, vosotros recibiréis la corona incorruptible de gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 5, 'Igualmente, mancebos, sed sujetos á los ancianos; y todos sumisos unos á otros, revestíos de humildad; porque Dios resiste á los soberbios, y da gracia á los humildes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 6, 'Humillaos pues bajo la poderosa mano de Dios, para que él os ensalce cuando fuere tiempo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 7, 'Echando toda vuestra solicitud en él, porque él tiene cuidado de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 8, 'Sed templados, y velad; porque vuestro adversario el diablo, cual león rugiente, anda alrededor buscando á quien devore:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 9, 'Al cual resistid firmes en la fe, sabiendo que las mismas aflicciones han de ser cumplidas en la compañía de vuestros hermanos que están en el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 10, 'Mas el Dios de toda gracia, que nos ha llamado á su gloria eterna por Jesucristo, después que hubiereis un poco de tiempo padecido, él mismo os perfeccione, coforme, corrobore y establezca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 11, 'A él sea gloria é imperio para siempre. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 12, 'Por Silvano, el hermano fiel, según yo pienso, os he escrito brevemente, amonestándo os, y testificando que ésta es la verdadera gracia de Dios, en la cual estáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 13, 'La iglesia que está en Babilonia, juntamente elegida con vosotros, os saluda, y Marcos mi hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1PE', '1 Pedro', 5, 14, 'Saludaos unos á otros con ósculo de caridad. Paz sea con todos vosotros los que estáis en Jesucristo. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 1, 'SIMON Pedro, siervo y apóstol de Jesucristo, á los que habéis alcanzado fe igualmente preciosa con nosotros en la justicia de nuestro Dios y Salvador Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 2, 'Gracia y paz os sea multiplicada en el conocimiento de Dios, y de nuestro Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 3, 'Como todas las cosas que pertenecen á la vida y á la piedad nos sean dadas de su divina potencia, por el conocimiento de aquel que nos ha llamado por su gloria y virtud:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 4, 'Por las cuales nos son dadas preciosas y grandísimas promesas, para que por ellas fueseis hechos participantes de la naturaleza divina, habiendo huído de la corrupción que está en el mundo por concupiscencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 5, 'Vosotros también, poniendo toda diligencia por esto mismo, mostrad en vuestra fe virtud, y en la virtud ciencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 6, 'Y en la ciencia templanza, y en la templanza paciencia, y en la paciencia temor de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 7, 'Y en el temor de Dios, amor fraternal, y en el amor fraternal caridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 8, 'Porque si en vosotros hay estas cosas, y abundan, no os dejarán estar ociosos, ni estériles en el conocimiento de nuestro Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 9, 'Mas el que no tiene estas cosas, es ciego, y tiene la vista muy corta, habiendo olvidado la purificación de sus antiguos pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 10, 'Por lo cual, hermanos, procurad tanto más de hacer firme vuestra vocación y elección; porque haciendo estas cosas, no caeréis jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 11, 'Porque de esta manera os será abundantemente administrada la entrada en el reino eterno de nuestro Señor y Salvador Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 12, 'Por esto, yo no dejaré de amonestaros siempre de estas cosas, aunque vosotros las sepáis, y estéis confirmados en la verdad presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 13, 'Porque tengo por justo, en tanto que estoy en este tabernáculo, de incitaros con amonestación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 14, 'Sabiendo que brevemente tengo de dejar mi tabernáculo, como nuestro Señor Jesucristo me ha declarado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 15, 'También yo procuraré con diligencia, que después de mi fallecimiento, vosotros podáis siempre tener memoria de estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 16, 'Porque no os hemos dado á conocer la potencia y la venida de nuestro Señor Jesucristo, siguiendo fábulas por arte compuestas; sino como habiendo con nuestros propios ojos visto su majestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 17, 'Porque él había recibido de Dios Padre honra y gloria, cuando una tal voz fué á él enviada de la magnífica gloria: Este es el amado Hijo mío, en el cual yo me he agradado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 18, 'Y nosotros oímos esta voz enviada del cielo, cuando estábamos juntamente con él en el monte santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 19, 'Tenemos también la palabra profética más permanente, á la cual hacéis bien de estar atentos como á una antorcha que alumbra en lugar oscuro hasta que el día esclarezca, y el lucero de la mañana salga en vuestros corazones:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 20, 'Entendiendo primero esto, que ninguna profecía de la Escritura es de particular interpretación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 1, 21, 'Porque la profecía no fué en los tiempos pasados traída por voluntad humana, sino los santos hombres de Dios hablaron siendo inspirados del Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 1, 'PERO hubo también falsos profetas en el pueblo, como habrá entre vosotros falsos doctores, que introducirán encubiertamente herejías de perdición, y negarán al Señor que los rescató, atrayendo sobre sí mismos perdición acelerada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 2, 'Y muchos seguirán sus disoluciones, por los cuales el camino de la verdad será blasfemado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 3, 'Y por avaricia harán mercadería de vosotros con palabras fingidas, sobre los cuales la condenación ya de largo tiempo no se tarda, y su perdición no se duerme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 4, 'Porque si Dios no perdonó á los ángeles que habían pecado, sino que habiéndolos despeñado en el infierno con cadenas de oscuridad, los entregó para ser reservados al juicio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 5, 'Y si no perdonó al mundo viejo, mas guardó á Noé, pregonero de justicia, con otras siete personas, trayendo el diluvio sobre el mundo de malvados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 6, 'Y si condenó por destrucción las ciudades de Sodoma y de Gomorra, tornándolas en ceniza, y poniéndolas por ejemplo á los que habían de vivir sin temor y reverencia de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 7, 'Y libró al justo Lot, acosado por la nefanda conducta de los malvados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 8, '(Porque este justo, con ver y oir, morando entre ellos, afligía cada día su alma justa con los hechos de aquellos injustos;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 9, 'Sabe el Señor librar de tentación á los píos, y reservar á los injustos para ser atormentados en el día del juicio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 10, 'Y principalmente á aquellos que, siguiendo la carne, andan en concupiscencia é inmundicia, y desprecian la potestad; atrevidos, contumaces, que no temen decir mal de las potestades superiores:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 11, 'Como quiera que los mismos ángeles, que son mayores en fuerza y en potencia, no pronuncian juicio de maldición contra ellas delante del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 12, 'Mas éstos, diciendo mal de las cosas que no entienden, como bestias brutas, que naturalmente son hechas para presa y destrucción, perecerán en su perdición,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 13, 'Recibiendo el galardón de su injusticia, ya que reputan por delicia poder gozar de deleites cada día. Estos son suciedades y manchas, los cuales comiendo con vosotros, juntamente se recrean en sus errores;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 14, 'Teniendo los ojos llenos de adulterio, y no saben cesar de pecar; cebando las almas inconstantes; teniendo el corazón ejercitado en codicias, siendo hijos de maldición;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 15, 'Que han dejado el camino derecho, y se han extraviado, siguiendo el camino de Balaam, hijo de Bosor, el cual amó el premio de la maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 16, 'Y fué reprendido por su iniquidad: una muda bestia de carga, hablando en voz de hombre, refrenó la locura del profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 17, 'Estos son fuentes sin agua, y nubes traídas de torbellino de viento: para los cuales está guardada la oscuridad de las tinieblas para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 18, 'Porque hablando arrogantes palabras de vanidad, ceban con las concupiscencias de la carne en disoluciones á los que verdaderamente habían huído de los que conversan en error;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 19, 'Prometiéndoles libertad, siendo ellos mismos siervos de corrupción. Porque el que es de alguno vencido, es sujeto á la servidumbre del que lo venció.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 20, 'Ciertamente, si habiéndose ellos apartado de las contaminaciones del mundo, por el conocimiento del Señor y Salvador Jesucristo, y otra vez envolviéndose en ellas, son vencidos, sus postrimerías les son hechas peores que los principios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 21, 'Porque mejor les hubiera sido no haber conocido el camino de la justicia, que después de haberlo conocido, tornarse atrás del santo mandamiento que les fué dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 2, 22, 'Pero les ha acontecido lo del verdadero proverbio: El perro se volvió á su vómito, y la puerca lavada á revolcarse en el cieno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 1, 'CARISIMOS, yo os escribo ahora esta segunda carta, por las cuales ambas despierto con exhortación vuestro limpio entendimiento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 2, 'Para que tengáis memoria de las palabras que antes han sido dichas por los santos profetas, y de nuestro mandamiento, que somos apóstoles del Señor y Salvador:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 3, 'Sabiendo primero esto, que en los postrimeros días vendrán burladores, andando según sus propias concupiscencias,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 4, 'Y diciendo: ¿Dónde está la promesa de su advenimiento? porque desde el día en que los padres durmieron, todas las cosas permanecen así como desde el principio de la creación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 5, 'Cierto ellos ignoran voluntariamente, que los cielos fueron en el tiempo antiguo, y la tierra que por agua y en agua está asentada, por la palabra de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 6, 'Por lo cual el mundo de entonces pereció anegado en agua:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 7, 'Mas los cielos que son ahora, y la tierra, son conservados por la misma palabra, guardados para el fuego en el día del juicio, y de la perdición de los hombres impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 8, 'Mas, oh amados, no ignoréis esta una cosa: que un día delante del Señor es como mil años y mil años como un día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 9, 'El Señor no tarda su promesa, como algunos la tienen por tardanza; sino que es paciente para con nosotros, no queriendo que ninguno perezca, sino que todos procedan al arrepentimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 10, 'Mas el día del Señor vendrá como ladrón en la noche; en el cual los cielos pasarán con grande estruendo, y los elementos ardiendo serán deshechos, y la tierra y las obras que en ella están serán quemadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 11, 'Pues como todas estas cosas han de ser deshechas, ¿qué tales conviene que vosotros seáis en santas y pías conversaciones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 12, 'Esperando y apresurándoos para la venida del día de Dios, en el cual los cielos siendo encendidos serán deshechos, y los elementos siendo abrasados, se fundirán?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 13, 'Bien que esperamos cielos nuevos y tierra nueva, según sus promesas, en los cuales mora la justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 14, 'Por lo cual, oh amados, estando en esperanza de estas cosas, procurad con diligencia que seáis hallados de él sin mácula, y sin reprensión, en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 15, 'Y tened por salud la paciencia de nuestro Señor; como también nuestro amado hermano Pablo, según la sabiduría que le ha sido dada, os ha escrito también;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 16, 'Casi en todas sus epístolas, hablando en ellas de estas cosas; entre las cuales hay algunas difíciles de entender, las cuales los indoctos é inconstantes tuercen, como también las otras Escrituras, para perdición de sí mismos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 17, 'Así que vosotros, oh amados, pues estáis amonestados, guardaos que por el error de los abominables no seáis juntamente extraviados, y caigáis de vuestra firmeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2PE', '2 Pedro', 3, 18, 'Mas creced en la gracia y conocimiento de nuestro Señor y Salvador Jesucristo. A él sea gloria ahora y hasta el día de la eternidad. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 1, 'LO que era desde el principio, lo que hemos oído, lo que hemos visto con nuestros ojos, lo que hemos mirado, y palparon nuestras manos tocante al Verbo de vida;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 2, '(Porque la vida fué manifestada, y vimos, y testificamos, y os anunciamos aquella vida eterna, la cual estaba con el Padre, y nos ha aparecido;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 3, 'Lo que hemos visto y oído, eso os anunciamos, para que también vosotros tengáis comunión con nosotros: y nuestra comunión verdaderamente es con el Padre, y con su Hijo Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 4, 'Y estas cosas os escribimos, para que vuestro gozo sea cumplido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 5, 'Y este es el mensaje que oímos de él, y os anunciamos: Que Dios es luz, y en él no hay ningunas tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 6, 'Si nosotros dijéremos que tenemos comunión con él, y andamos en tinieblas, mentimos, y no hacemos la verdad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 7, 'Mas si andamos en luz, como él está en luz, tenemos comunión entre nosotros, y la sangre de Jesucristo su Hijo nos limpia de todo pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 8, 'Si dijéremos que no tenemos pecado, nos engañamos á nosotros mismos, y no hay verdad en nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 9, 'Si confesamos nuestros pecados, él es fiel y justo para que nos perdone nuestros pecados, y nos limpie de toda maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 1, 10, 'Si dijéremos que no hemos pecado, lo hacemos á él mentiroso, y su palabra no está en nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 1, 'HIJITOS míos, estas cosas os escribo, para que no pequéis; y si alguno hubiere pecado, abogado tenemos para con el Padre, á Jesucristo el justo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 2, 'Y él es la propiciación por nuestros pecados: y no solamente por los nuestros, sino también por los de todo el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 3, 'Y en esto sabemos que nosotros le hemos conocido, si guardamos sus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 4, 'El que dice, Yo le he conocido, y no guarda sus mandamientos, el tal es mentiroso, y no hay verdad en él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 5, 'Mas el que guarda su palabra, la caridad de Dios está verdaderamente perfecta en él: por esto sabemos que estamos en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 6, 'El que dice que está en él, debe andar como él anduvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 7, 'Hermanos, no os escribo mandamiento nuevo, sino el mandamiento antiguo que habéis tenido desde el principio: el mandamiento antiguo es la palabra que habéis oído desde el principio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 8, 'Otra vez os escribo un mandamiento nuevo, que es verdadero en él y en vosotros; porque las tinieblas son pasadas, y la verdadera luz ya alumbra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 9, 'El que dice que está en luz, y aborrece á su hermano, el tal aun está en tinieblas todavía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 10, 'El que ama á su hermano, está en luz, y no hay tropiezo en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 11, 'Mas el que aborrece á su hermano, está en tinieblas, y anda en tinieblas, y no sabe á donde va; porque las tinieblas le han cegado los ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 12, 'Os escribo á vosotros, hijitos, porque vuestros pecados os son perdonados por su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 13, 'Os escribo á vosotros, padres, porque habéis conocido á aquel que es desde el principio. Os escribo á vosotros, mancebos, porque habéis vencido al maligno. Os escribo á vosotros, hijitos, porque habéis conocido al Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 14, 'Os he escrito á vosotros, padres, porque habéis conocido al que es desde el principio. Os he escrito á vosotros, mancebos, porque sois fuertes, y la palabra de Dios mora en vosotros, y habéis vencido al maligno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 15, 'No améis al mundo, ni las cosas que están en el mundo. Si alguno ama al mundo, el amor del Padre no está en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 16, 'Porque todo lo que hay en el mundo, la concupiscencia de la carne, y la concupiscencia de los ojos, y la soberbia de la vida, no es del Padre, mas es del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 17, 'Y el mundo se pasa, y su concupiscencia; mas el que hace la voluntad de Dios, permanece para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 18, 'Hijitos, ya es el último tiempo: y como vosotros habéis oído que el anticristo ha de venir, así también al presente han comenzado á ser muchos anticristos; por lo cual sabemos que es el último tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 19, 'Salieron de nosotros, mas no eran de nosotros; porque si fueran de nosotros, hubieran cierto permanecido con nosotros; pero salieron para que se manifestase que todos no son de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 20, 'Mas vosotros tenéis la unción del Santo, y conocéis todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 21, 'No os he escrito como si ignoraseis la verdad, sino como á los que la conocéis, y que ninguna mentira es de la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 22, '¿Quién es mentiroso, sino el que niega que Jesús es el Cristo? Este tal es anticristo, que niega al Padre y al Hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 23, 'Cualquiera que niega al Hijo, este tal tampoco tiene al Padre. Cualquiera que confiese al Hijo tiene también al Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 24, 'Pues lo que habéis oído desde el principio, sea permaneciente en vosotros. Si lo que habéis oído desde el principio fuere permaneciente en vosotros, también vosotros permaneceréis en el Hijo y en el Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 25, 'Y esta es la promesa, la cual él nos prometió, la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 26, 'Os he escrito esto sobre los que os engañan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 27, 'Pero la unción que vosotros habéis recibido de él, mora en vosotros, y no tenéis necesidad que ninguno os enseñe; mas como la unción misma os enseña de todas cosas, y es verdadera, y no es mentira, así como os ha enseñado, perseveraréis en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 28, 'Y ahora, hijitos, perseverad en él; para que cuando apareciere, tengamos confianza, y no seamos confundidos de él en su venida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 2, 29, 'Si sabéis que él es justo, sabed también que cualquiera que hace justicia, es nacido de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 1, 'MIRAD cuál amor nos ha dado el Padre, que seamos llamados hijos de Dios: por esto el mundo no nos conoce, porque no le conoce á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 2, 'Muy amados, ahora somos hijos de Dios, y aun no se ha manifestado lo que hemos de ser; pero sabemos que cuando él apareciere, seremos semejantes á él, porque le veremos como él es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 3, 'Y cualquiera que tiene esta esperanza en él, se purifica, como él también es limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 4, 'Cualquiera que hace pecado, traspasa también la ley; pues el pecado es transgresión de la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 5, 'Y sabéis que él apareció para quitar nuestros pecados, y no hay pecado en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 6, 'Cualquiera que permanece en él, no peca; cualquiera que peca, no le ha visto, ni le ha conocido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 7, 'Hijitos, no os engañe ninguno: el que hace justicia, es justo, como él también es justo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 8, 'El que hace pecado, es del diablo; porque el diablo peca desde el principio. Para esto apareció el Hijo de Dios, para deshacer las obras del diablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 9, 'Cualquiera que es nacido de Dios, no hace pecado, porque su simiente está en él; y no puede pecar, porque es nacido de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 10, 'En esto son manifiestos los hijos de Dios, y los hijos del diablo: cualquiera que no hace justicia, y que no ama á su hermano, no es de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 11, 'Porque, este es el mensaje que habéis oído desde el principio: Que nos amemos unos á otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 12, 'No como Caín, que era del maligno, y mató á su hermano. ¿Y por qué causa le mató? Porque sus obras eran malas, y las de su hermano justas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 13, 'Hermanos míos, no os maravilléis si el mundo os aborrece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 14, 'Nosotros sabemos que hemos pasado de muerte á vida, en que amamos á los hermanos. El que no ama á su hermano, está en muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 15, 'Cualquiera que aborrece á su hermano, es homicida; y sabéis que ningún homicida tiene vida eterna permaneciente en sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 16, 'En esto hemos conocido el amor, porque él puso su vida por nosotros: también nosotros debemos poner nuestras vidas por los hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 17, 'Mas el que tuviere bienes de este mundo, y viere á su hermano tener necesidad, y le cerrare sus entrañas, ¿cómo está el amor de Dios en él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 18, 'Hijitos míos, no amemos de palabra ni de lengua, sino de obra y en verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 19, 'Y en esto conocemos que somos de la verdad, y tenemos nuestros corazones certificados delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 20, 'Porque si nuestro corazón nos reprendiere, mayor es Dios que nuestro corazón, y conoce todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 21, 'Carísimos, si nuestro corazón no nos reprende, confianza tenemos en Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 22, 'Y cualquier cosa que pidiéremos, la recibiremos de él, porque guardamos sus mandamientos, y hacemos las cosas que son agradables delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 23, 'Y éste es su mandamiento: Que creamos en el nombre de su Hijo Jesucristo, y nos amemos unos á otros como nos lo ha mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 3, 24, 'Y el que guarda sus mandamientos, está en él, y él en él. Y en esto sabemos que él permanece en nosotros, por el Espíritu que nos ha dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 1, 'AMADOS, no creáis á todo espíritu, sino probad los espíritus si son de Dios; porque muchos falsos profetas son salidos en el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 2, 'En esto conoced el Espíritu de Dios: todo espíritu que confiesa que Jesucristo es venido en carne es de Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 3, 'Y todo espíritu que no confiesa que Jesucristo es venido en carne, no es de Dios: y éste es el espíritu del anticristo, del cual vosotros habéis oído que ha de venir, y que ahora ya está en el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 4, 'Hijitos, vosotros sois de Dios, y los habéis vencido; porque el que en vosotros está, es mayor que el que está en el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 5, 'Ellos son del mundo; por eso hablan del mundo, y el mundo los oye.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 6, 'Nosotros somos de Dios: el que conoce á Dios, nos oye: el que no es de Dios, no nos oye. Por esto conocemos el espíritu de verdad y el espíritu de error.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 7, 'Carísimos, amémonos unos á otros; porque el amor es de Dios. Cualquiera que ama, es nacido de Dios, y conoce á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 8, 'El que no ama, no conoce á Dios; porque Dios es amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 9, 'En esto se mostró el amor de Dios para con nosotros, en que Dios envió á su Hijo unigénito al mundo, para que vivamos por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 10, 'En esto consiste el amor: no que nosotros hayamos amado á Dios, sino que él nos amó á nosotros, y ha enviado á su Hijo en propiciación por nuestros pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 11, 'Amados, si Dios así nos ha amado, debemos también nosotros amarnos unos á otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 12, 'Ninguno vió jamás á Dios. Si nos amamos unos á otros, Dios está en nosotros, y su amor es perfecto en nosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 13, 'En esto conocemos que estamos en él, y él en nosotros, en que nos ha dado de su Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 14, 'Y nosotros hemos visto y testificamos que el Padre ha enviado al Hijo para ser Salvador del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 15, 'Cualquiera que confesare que Jesús es el Hijo de Dios, Dios está en él, y él en Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 16, 'Y nosotros hemos conocido y creído el amor que Dios tiene para con nosotros. Dios es amor; y el que vive en amor, vive en Dios, y Dios en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 17, 'En esto es perfecto el amor con nosotros, para que tengamos confianza en el día del juicio; pues como él es, así somos nosotros en este mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 18, 'En amor no hay temor; mas el perfecto amor echa fuera el temor: porque el temor tiene pena. De donde el que teme, no está perfecto en el amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 19, 'Nosotros le amamos á él, porque él nos amó primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 20, 'Si alguno dice, Yo amo á Dios, y aborrece á su hermano, es mentiroso. Porque el que no ama á su hermano al cual ha visto, ¿cómo puede amar á Dios á quien no ha visto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 4, 21, 'Y nosotros tenemos este mandamiento de él: Que el que ama á Dios, ame también á su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 1, 'TODO aquel que cree que Jesús es el Cristo, es nacido de Dios: y cualquiera que ama al que ha engendrado, ama también al que es nacido de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 2, 'En esto conocemos que amamos á los hijos de Dios, cuando amamos á Dios, y guardamos sus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 3, 'Porque este es el amor de Dios, que guardemos sus mandamientos; y sus mandamientos no son penosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 4, 'Porque todo aquello que es nacido de Dios vence al mundo: y esta es la victoria que vence al mundo, nuestra fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 5, '¿Quién es el que vence al mundo, sino el que cree que Jesús es el Hijo de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 6, 'Este es Jesucristo, que vino por agua y sangre: no por agua solamente, sino por agua y sangre. Y el Espíritu es el que da testimonio: porque el Espírtiu es la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 7, 'Porque tres son los que dan testimonio en el cielo, el Padre, el Verbo, y el Espíritu Santo: y estos tres son uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 8, 'Y tres son los que dan testimonio en la tierra, el Espíritu, y el agua, y la sangre: y estos tres concuerdan en uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 9, 'Si recibimos el testimonio de los hombres, el testimonio de Dios es mayor; porque éste es el testimonio de Dios, que ha testificado de su Hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 10, 'El que cree en el Hijo de Dios, tiene el testimonio en sí mismo: el que no cree á Dios, le ha hecho mentiroso; porque no ha creído en el testimonio que Dios ha testificado de su Hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 11, 'Y este es el testimonio: Que Dios nos ha dado vida eterna; y esta vida está en su Hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 12, 'El que tiene al Hijo, tiene al vida: el que no tiene la Hijo de Dios, no tiene la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 13, 'Estas cosas he escrito á vosotros que creéis en el nombre del Hijo de Dios, para que sepáis que tenéis vida eterna, y para que creáis en el nombre del Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 14, 'Y esta es la confianza que tenemos en él, que si demandáremos alguna cosa conforme á su voluntad, él nos oye.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 15, 'Y si sabemos que él nos oye en cualquiera cosa que demandáremos, sabemos que tenemos las peticiones que le hubiéremos demandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 16, 'Si alguno viere cometer á su hermano pecado no de muerte, demandará y se le dará vida; digo á los que pecan no de muerte. Hay pecado de muerte, por el cual yo no digo que ruegue.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 17, 'Toda maldad es pecado; mas hay pecado no de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 18, 'Sabemos que cualquiera que es nacido de Dios, no peca; mas el que es engendrado de Dios, se guarda á sí mismo, y el maligno no le toca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 19, 'Sabemos que somos de Dios, y todo el mundo está puesto en maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 20, 'Empero sabemos que el Hijo de Dios es venido, y nos ha dado entendimiento para conocer al que es verdadero: y estamos en el verdadero, en su Hijo Jesucristo. Este es el verdadero Dios, y la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1JN', '1 Juan', 5, 21, 'Hijitos, guardaos de los ídolos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 1, 'EL anciano á la señora elegida y á sus hijos, á los cuales yo amo en verdad y no yo solo, sino también todos los que han conocido la verdad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 2, 'Por la verdad que está en nosotros, y será perpetuamente con nosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 3, 'Sea con vosotros gracia, misericordia, y paz de Dios Padre, y del Señor Jesucristo, Hijo del Padre, en verdad y en amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 4, 'Mucho me he gozado, porque he hallado de tus hijos, que andan en verdad, como nosotros hemos recibido el mandamiento del Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 5, 'Y ahora te ruego, señora, no como escribiéndote un nuevo mandamiento, sino aquel que nosotros hemos tenido desde el principio, que nos amemos unos á otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 6, 'Y este es amor, que andemos según sus mandamientos. Este es el mandamiento: Que andéis en él, como vosotros habéis oído desde el principio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 7, 'Porque muchos engañadores son entrados en el mundo, los cuales no confiesan que Jesucristo ha venido en carne. Este tal el engañador es, y el anticristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 8, 'Mirad por vosotros mismos, porque no perdamos las cosas que hemos obrado, sino que recibamos galardón cumplido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 9, 'Cualquiera que se rebela, y no persevera en la doctrina de Cristo, no tiene á Dios: el que persevera en la doctrina de Cristo, el tal tiene al Padre y al Hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 10, 'Si alguno viene á vosotros, y no trae esta doctrina, no lo recibáis en casa, ni le digáis: ¡bienvenido!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 11, 'Porque el que le dice bienvenido, comunica con sus malas obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 12, 'Aunque tengo muchas cosas que escribiros, no he querido comunicarlas por medio de papel y tinta; mas espero ir á vosotros, y hablar boca á boca, para que nuestro gozo sea cumplido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2JN', '2 Juan', 1, 13, 'Los hijos de tu hermana elegida te saludan. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 1, 'EL anciano al muy amado Gaio, al cual yo amo en verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 2, 'Amado, yo deseo que tú seas prosperado en todas cosas, y que tengas salud, así como tu alma está en prosperidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 3, 'Ciertamente me gocé mucho cuando vinieron los hermanos y dieron testimonio de tu verdad, así como tú andas en la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 4, 'No tengo yo mayor gozo que éste, el oir que mis hijos andan en la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 5, 'Amado, fielmente haces todo lo que haces para con los hermanos, y con los extranjeros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 6, 'Los cuales han dado testimonio de tu amor en presencia de la iglesia: á los cuales si ayudares como conviene según Dios, harás bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 7, 'Porque ellos partieron por amor de su nombre, no tomando nada de los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 8, 'Nosotros, pues, debemos recibir á los tales, para que seamos cooperadores á la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 9, 'Yo he escrito á la iglesia: mas Diótrefes, que ama tener el primado entre ellos, no nos recibe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 10, 'Por esta causa, si yo viniere, recordaré las obras que hace parlando con palabras maliciosas contra nosotros; y no contento con estas cosas, no recibe á los hermanos, y prohibe á los que los quieren recibir, y los echa de la iglesia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 11, 'Amado, no sigas lo que es malo, sino lo que es bueno. El que hace bien es de Dios: mas el que hace mal, no ha visto á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 12, 'Todos dan testimonio de Demetrio, y aun la misma verdad: y también nosotros damos testimonio; y vosotros habéis conocido que nuestro testimonio es verdadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 13, 'Yo tenía muchas cosas que escribirte; empero no quiero escribirte por tinta y pluma:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('3JN', '3 Juan', 1, 14, 'Porque espero verte en breve, y hablaremos boca á boca. sea contigo. Los amigos te saludan. Saluda tú á los amigos por nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 1, 'JUDAS, siervo de Jesucristo, y hermano de Jacobo, á los llamados, santificados en Dios Padre, y conservados en Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 2, 'Misericordia, y paz, y amor os sean multiplicados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 3, 'Amados, por la gran solicitud que tenía de escribiros de la común salud, me ha sido necesario escribiros amonestándoos que contendáis eficazmente por la fe que ha sido una vez dada á los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 4, 'Porque algunos hombres han entrado encubiertamente, los cuales desde antes habían estado ordenados para esta condenación, hombres impíos, convirtiendo la gracia de nuestro Dios en disolución, y negando á Dios que solo es el que tiene dominio, y á nuestro Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 5, 'Os quiero pues amonestar, ya que alguna vez habéis sabido esto, que el Señor habiendo salvado al pueblo de Egipto, después destruyó á los que no creían:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 6, 'Y á los ángeles que no guardaron su dignidad, mas dejaron su habitación, los ha reservado debajo de oscuridad en prisiones eternas hasta el juicio del gran día:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 7, 'Como Sodoma y Gomorra, y las ciudades comarcanas, las cuales de la misma manera que ellos habían fornicado, y habían seguido la carne extraña, fueron puestas por ejemplo: sufriendo el juicio del fuego eterno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 8, 'De la misma manera también estos soñadores amancillan la carne, y menosprecian la potestad, y vituperan las potestades superiores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 9, 'Pero cuando el arcángel Miguel contendía con el diablo, disputando sobre el cuerpo de Moisés, no se atrevió á usar de juicio de maldición contra él, sino que dijo: El Señor te reprenda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 10, 'Pero éstos maldicen las cosas que no conocen; y las cosas que naturalmente conocen, se corrompen en ellas, como bestias brutas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 11, '¡Ay de ellos! porque han seguido el camino de Caín, y se lanzaron en el error de Balaam por recompensa, y perecieron en la contradicción de Coré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 12, 'Estos son manchas en vuestros convites, que banquetean juntamente, apacentándose á sí mismos sin temor alguno: nubes sin agua, las cuales son llevadas de acá para allá de los vientos: árboles marchitos como en otoño, sin fruto, dos veces muertos y desarraigados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 13, 'Fieras ondas de la mar, que espuman sus mismas abominaciones; estrellas erráticas, á las cuales es reservada eternalmente la oscuridad de las tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 14, 'De los cuales también profetizó Enoc, séptimo desde Adam, diciendo: He aquí, el Señor es venido con sus santos millares,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 15, 'A hacer juicio contra todos, y á convencer á todos los impíos de entre ellos tocante á todas sus obras de impiedad que han hecho impíamente, y á todas las cosas duras que los pecadores impíos han hablado contra él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 16, 'Estos son murmuradores, querellosos, andando según sus deseos; y su boca habla cosas soberbias, teniendo en admiración las personas por causa del provecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 17, 'Mas vosotros, amados, tened memoria de las palabras que antes han sido dichas por los apóstoles de nuestro Señor Jesucristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 18, 'Como os decían: Que en el postrer tiempo habría burladores, que andarían según sus malvados deseos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 19, 'Estos son los que hacen divisiones, sensuales, no teniendo el Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 20, 'Mas vosotros, oh amados, edificándoos sobre vuestra santísima fe, orando por el Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 21, 'Conservaos en el amor de Dios, esperando la misericordia de nuestro Señor Jesucristo, para vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 22, 'Y recibid á los unos en piedad, discerniendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 23, 'Mas haced salvos á los otros por temor, arrebatándolos del fuego; aborreciendo aun la ropa que es contaminada de la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 24, 'A aquel, pues, que es poderoso para guardaros sin caída, y presentaros delante de su gloria irreprensibles, con grande alegría,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JUD', 'Judas', 1, 25, 'Al Dios solo sabio, nuestro Salvador, sea gloria y magnificencia, imperio y potencia, ahora y en todos los siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 1, 'LA revelación de Jesucristo, que Dios le dió, para manifestar á sus siervos las cosas que deben suceder presto; y la declaró, enviándo la por su ángel á Juan su siervo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 2, 'El cual ha dado testimonio de la palabra de Dios, y del testimonio de Jesucristo, y de todas las cosas que ha visto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 3, 'Bienaventurado el que lee, y los que oyen las palabras de esta profecía, y guardan las cosas en ella escritas: porque el tiempo está cerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 4, 'Juan á las siete iglesias que están en Asia: Gracia sea con vosotros, y paz del que es y que era y que ha de venir, y de los siete Espíritus que están delante de su trono;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 5, 'Y de Jesucristo, el testigo fiel, el primogénito de los muertos, y príncipe de los reyes de la tierra. Al que nos amó, y nos ha lavado de nuestros pecados con su sangre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 6, 'Y nos ha hecho reyes y sacerdotes para Dios y su Padre; á él sea gloria é imperio para siempre jamás. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 7, 'He aquí que viene con las nubes, y todo ojo le verá, y los que le traspasaron; y todos los linajes de la tierra se lamentarán sobre él. Así sea. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 8, 'Yo soy el Alpha y la Omega, principio y fin, dice el Señor, que es y que era y que ha de venir, el Todopoderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 9, 'Yo Juan, vuestro hermano, y participante en la tribulación y en el reino, y en la paciencia de Jesucristo, estaba en la isla que es llamada Patmos, por la palabra de Dios y el testimonio de Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 10, 'Yo fuí en el Espíritu en el día del Señor, y oí detrás de mí una gran voz como de trompeta,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 11, 'Que decía: Yo soy el Alpha y Omega, el primero y el último. Escribe en un libro lo que ves, y envía lo á las siete iglesias que están en Asia; á Efeso, y á Smirna, y á Pérgamo, y á Tiatira, y á Sardis, y á Filadelfia, y á Laodicea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 12, 'Y me volví á ver la voz que hablaba conmigo: y vuelto, vi siete candeleros de oro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 13, 'Y en medio de los siete candeleros, uno semejante al Hijo del hombre, vestido de una ropa que llegaba hasta los pies, y ceñido por los pechos con una cinta de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 14, 'Y su cabeza y sus cabellos eran blancos como la lana blanca, como la nieve; y sus ojos como llama de fuego;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 15, 'Y sus pies semejantes al latón fino, ardientes como en un horno; y su voz como ruido de muchas aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 16, 'Y tenía en su diestra siete estrellas: y de su boca salía una espada aguda de dos filos. Y su rostro era como el sol cuando resplandece en su fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 17, 'Y fpicuando yo le vi, caí como muerto á sus pies. Y él puso su diestra sobre mí, diciéndome: No temas: yo soy el primero y el último;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 18, 'Y el que vivo, y he sido muerto; y he aquí que vivo por siglos de siglos, Amén. Y tengo las llaves del infierno y de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 19, 'Escribe las cosas que has visto, y las que son, y las que han de ser después de éstas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 1, 20, 'El misterio de las siete estrellas que has visto en mi diestra, y los siete candeleros de oro. Las siete estrellas son los ángeles de las siete iglesias; y los siete candeleros que has visto, son las siete iglesias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 1, 'ESCRIBE al ángel de la iglesia en EFESO: El que tiene las siete estrellas en su diestra, el cual anda en medio de los siete candeleros de oro, dice estas cosas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 2, 'Yo sé tus obras, y tu trabajo y paciencia; y que tú no puedes sufrir los malos, y has probado á los que se dicen ser apóstoles, y no lo son, y los has hallado mentirosos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 3, 'Y has sufrido, y has tenido paciencia, y has trabajado por mi nombre, y no has desfallecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 4, 'Pero tengo contra ti que has dejado tu primer amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 5, 'Recuerda por tanto de dónde has caído, y arrepiéntete, y haz las primeras obras; pues si no, vendré presto á ti, y quitaré tu candelero de su lugar, si no te hubieres arrepentido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 6, 'Mas tienes esto, que aborreces los hechos de los Nicolaítas; los cuales yo también aborrezco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 7, 'El que tiene oído, oiga lo que el Espíritu dice á las iglesias. Al que venciere, daré á comer del árbol de la vida, el cual está en medio del paraíso de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 8, 'Y escribe al ángel de la iglesia en SMIRNA: El primero y postrero, que fué muerto, y vivió, dice estas cosas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 9, 'Yo sé tus obras, y tu tribulacion, y tu pobreza (pero tú eres rico), y la blasfemia de los que se dicen ser Judíos, y no lo son, mas son sinagoga de Satanás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 10, 'No tengas ningún temor de las cosas que has de padecer. He aquí, el diablo ha de enviar algunos de vosotros á la cárcel, para que seáis probados, y tendréis tribulación de diez días. Sé fiel hasta la muerte, y yo te daré la corona de la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 11, 'El que tiene oído, oiga lo que el Espíritu dice á las iglesias. El que venciere, no recibirá daño de la muerte segunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 12, 'Y escribe al ángel de la iglesia en PÉRGAMO: El que tiene la espada aguda de dos filos, dice estas cosas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 13, 'Yo sé tus obras, y dónde moras, donde está la silla de Satanás; y retienes mi nombre, y no has negado mi fe, aun en los días en que fué Antipas mi testigo fiel, el cual ha sido muerto entre vosotros, donde Satanás mora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 14, 'Pero tengo unas pocas cosas contra ti: porque tú tienes ahí los que tienen la doctrina de ahí los que tienen la doctrina de Fcbalaam, el cual enseñaba á Balac á poner escándalo delante de los hijos de Israel, á comer de cosas sacrificadas á los ídolos, y á cometer fornicación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 15, 'Así también tú tienes á los que tienen la doctrina de los Nicolaítas, lo cual yo aborrezco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 16, 'Arrepiéntete, porque de otra manera vendré á ti presto, y pelearé contra ellos con la espada de mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 17, 'El que tiene oído, oiga lo que el Espíritu dice á las iglesias. Al que venciere, daré á comer del maná escondido, y le daré una piedrecita blanca, y en la piedrecita un nombre nuevo escrito, el cual ninguno conoce sino aquel que lo recibe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 18, 'Y escribe al ángel de la iglesia en TIATIRA: El Hijo de Dios, que tiene sus ojos como llama de fuego, y sus pies semejantes al latón fino, dice estas cosas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 19, 'Yo he conocido tus obras, y caridad, y servicio, y fe, y tu paciencia, y que tus obras postreras son más que las primeras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 20, 'Mas tengo unas pocas cosas contra ti: porque permites aquella mujer Jezabel (que se dice profetisa) enseñar, y engañar á mis siervos, á fornicar, y á comer cosas ofrecidas á los ídolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 21, 'Y le he dado tiempo para que se arrepienta de la fornicación; y no se ha arrepentido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 22, 'He aquí, yo la echo en cama, y á los que adulteran con ella, en muy grande tribulación, si no se arrepintieren de sus obras:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 23, 'Y mataré á sus hijos con muerte; y todas las iglesias sabrán que yo soy el que escudriño los riñones y los corazones: y daré á cada uno de vosotros según sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 24, 'Pero yo digo á vosotros, y á los demás que estáis en Tiatira, cualesquiera que no tienen esta doctrina, y que no han conocido las profundidades de Satanás, como dicen: Yo no enviaré sobre vosotros otra carga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 25, 'Empero la que tenéis, tenedla hasta que yo venga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 26, 'Y al que hubiere vencido, y hubiere guardado mis obras hasta el fin, yo le daré potestad sobre las gentes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 27, 'Y las regirá con vara de hierro, y serán quebrantados como vaso de alfarero, como también yo he recibido de mi Padre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 28, 'Y le daré la estrella de la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 2, 29, 'El que tiene oído, oiga lo que el Espíritu dice á las iglesias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 1, 'Y ESCRIBE al ángel de la iglesia en SARDIS: El que tiene los siete Espíritus de Dios, y las siete estrellas, dice estas cosas: Yo conozco tus obras que tienes nombre que vives, y estás muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 2, 'Sé vigilante y confirma las otras cosas que están para morir; porque no he hallado tus obras perfectas delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 3, 'Acuérdate pues de lo que has recibido y has oído, y guárda lo, y arrepiéntete. Y si no velares, vendré á ti como ladrón, y no sabrás en qué hora vendré á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 4, 'Mas tienes unas pocas personas en Sardis que no han ensuciado sus vestiduras: y andarán conmigo en vestiduras blancas; porque son dignos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 5, 'El que venciere, será vestido de vestiduras blancas; y no borraré su nombre del libro de la vida, y confesaré su nombre delante de mi Padre, y delante de sus ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 6, 'El que tiene oído, oiga lo que el Espíritu dice á las iglesias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 7, 'Y escribe al ángel de la iglesia en FILADELFIA: Estas cosas dice el Santo, el Verdadero, el que tiene la llave de David, el que abre y ninguno cierra, y cierra y ninguno abre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 8, 'Yo conozco tus obras: he aquí, he dado una puerta abierta delante de ti, la cual ninguno puede cerrar; porque tienes un poco de potencia, y has guardado mi palabra, y no has negado mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 9, 'He aquí, yo doy de la sinagoga de Satanás, los que se dicen ser Judíos, y no lo son, mas mienten; he aquí, yo los constreñiré á que vengan y adoren delante de tus pies, y sepan que yo te he amado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 10, 'Porque has guardado la palabra de mi paciencia, yo también te guardaré de la hora de la tentación que ha de venir en todo el mundo, para probar á los que moran en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 11, 'He aquí, yo vengo presto; retén lo que tienes, para que ninguno tome tu corona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 12, 'Al que venciere, yo lo haré columna en el templo de mi Dios, y nunca más saldrá fuera; y escribiré sobre él el nombre de mi Dios, y el nombre de la ciudad de mi Dios, la nueva Jerusalem, la cual desciende del cielo de con mi Dios, y mi nombre nuevo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 13, 'El que tiene oído, oiga lo que el Espíritu dice á las iglesias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 14, 'Y escribe al ángel de la iglesia en LAODICEA: He aquí dice el Amén, el testigo fiel y verdadero, el principio de la creación de Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 15, 'Yo conozco tus obras, que ni eres frío, ni caliente. ¡Ojalá fueses frío, ó caliente!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 16, 'Mas porque eres tibio, y no frío ni caliente, te vomitaré de mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 17, 'Porque tú dices: Yo soy rico, y estoy enriquecido, y no tengo necesidad de ninguna cosa; y no conoces que tú eres un cuitado y miserable y pobre y ciego y desnudo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 18, 'Yo te amonesto que de mí compres oro afinado en fuego, para que seas hecho rico, y seas vestido de vestiduras blancas, para que no se descubra la vergüenza de tu desnudez; y unge tus ojos con colirio, para que veas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 19, 'Yo reprendo y castigo á todos los que amo: sé pues celoso, y arrepiéntete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 20, 'He aquí, yo estoy á la puerta y llamo: si alguno oyere mi voz y abriere la puerta, entraré á él, y cenaré con él, y él conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 21, 'Al que venciere, yo le daré que se siente conmigo en mi trono; así como yo he vencido, y me he sentado con mi Padre en su trono.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 3, 22, 'El que tiene oído, oiga lo que el Espíritu dice á las iglesias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 1, 'DESPUÉS de estas cosas miré, y he aquí una puerta abierta en el cielo: y la primera voz que oí, era como de trompeta que hablaba conmigo, diciendo: Sube acá, y yo te mostraré las cosas que han de ser después de éstas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 2, 'Y luego yo fuí en Espíritu: y he aquí, un trono que estaba puesto en el cielo, y sobre el trono estaba uno sentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 3, 'Y el que estaba sentado, era al parecer semejante á una piedra de jaspe y de sardio: y un arco celeste había alrededor del trono, semejante en el aspecto á la esmeralda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 4, 'Y alrededor del trono había veinticuatro sillas: y vi sobre las sillas veinticuatro ancianos sentados, vestidos de ropas blancas; y tenían sobre sus cabezas coronas de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 5, 'Y del trono salían relámpagos y truenos y voces: y siete lámparas de fuego estaban ardiendo delante del trono, las cuales son los siete Espíritus de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 6, 'Y delante del trono había como un mar de vidrio semejante al cristal; y en medio del trono, y alrededor del trono, cuatro animales llenos de ojos delante y detrás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 7, 'Y el primer animal era semejante á un león; y el segundo animal, semejante á un becerro; y el tercer animal tenía la cara como de hombre; y el cuarto animal, semejante á un águila volando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 8, 'Y los cuatro animales tenían cada uno por sí seis alas alrededor, y de dentro estaban llenos de ojos; y no tenían reposo día ni noche, diciendo: Santo, santo, santo el Señor Dios Todopoderoso, que era, y que es, y que ha de venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 9, 'Y cuando aquellos animales daban gloria y honra y alabanza al que estaba sentado en el trono, al que vive para siempre jamás,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 10, 'Los veinticuatro ancianos se postraban delante del que estaba sentado en el trono, y adoraban al que vive para siempre jamás, y echaban sus coronas delante del trono, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 4, 11, 'Señor, digno eres de recibir gloria y honra y virtud: porque tú criaste todas las cosas, y por tu voluntad tienen ser y fueron criadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 1, 'Y VI en la mano derecha del que estaba sentado sobre el trono un libro escrito de dentro y de fuera, sellado con siete sellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 2, 'Y vi un fuerte ángel predicando en alta voz: ¿Quién es digno de abrir el libro, y de desatar sus sellos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 3, 'Y ninguno podía, ni en el cielo, ni en la tierra, ni debajo de la tierra, abrir el libro, ni mirarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 4, 'Y yo lloraba mucho, porque no había sido hallado ninguno digno de abrir el libro, ni de leerlo, ni de mirarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 5, 'Y uno de los ancianos me dice: No llores: he aquí el león de la tribu de Judá, la raíz de David, que ha vencido para abrir el libro, y desatar sus siete sellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 6, 'Y miré; y he aquí en medio del trono y de los cuatro animales, y en medio de los ancianos, estaba un Cordero como inmolado, que tenía siete cuernos, y siete ojos, que son los siete Espíritus de Dios enviados en toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 7, 'Y él vino, y tomó el libro de la mano derecha de aquel que estaba sentado en el trono.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 8, 'Y cuando hubo tomado el libro, los cuatro animales y los veinticuatro ancianos se postraron delante del Cordero, teniendo cada uno arpas, y copas de oro llenas de perfumes, que son las oraciones de los santos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 9, 'Y cantaban un nuevo cántico, diciendo: Digno eres de tomar el libro, y de abrir sus sellos; porque tú fuiste inmolado, y nos has redimido para Dios con tu sangre, de todo linaje y lengua y pueblo y nación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 10, 'Y nos has hecho para nuestro Dios reyes y sacerdotes, y reinaremos sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 11, 'Y miré, y oí voz de muchos ángeles alrededor del trono, y de los animales, y de los ancianos; y la multitud de ellos era millones de millones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 12, 'Que decían en alta voz: El Cordero que fué inmolado es digno de tomar el poder y riquezas y sabiduría, y fortaleza y honra y gloria y alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 13, 'Y oí á toda criatura que está en el cielo, y sobre la tierra, y debajo de la tierra, y que está en el mar, y todas las cosas que en ellos están, diciendo: Al que está sentado en el trono, y al Cordero, sea la bendición, y la honra, y la gloria, y el poder, para siempre jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 5, 14, 'Y los cuatro animales decían: Amén. Y los veinticuatro ancianos cayeron sobre sus rostros, y adoraron al que vive para siempre jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 1, 'Y MIRÉ cuando el Cordero abrió uno de los sellos, y oí á uno los cuatro animales diciendo como con una voz de trueno: Ven y ve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 2, 'Y miré, y he aquí un caballo blanco: y el que estaba sentado encima de él, tenía un arco; y le fué dada una corona, y salió victorioso, para que también venciese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 3, 'Y cuando él abrió el segundo sello, oí al segundo animal, que decía: Ven y ve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 4, 'Y salió otro caballo bermejo: y al que estaba sentado sobre él, fué dado poder de quitar la paz de la tierra, y que se maten unos á otros: y fuéle dada una grande espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 5, 'Y cuando él abrió el tercer sello, oí al tercer animal, que decía: Ven y ve. Y miré, y he aquí un caballo negro: y el que estaba sentado encima de él, tenía un peso en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 6, 'Y oí una voz en medio de los cuatro animales, que decía: Dos libras de trigo por un denario, y seis libras de cebada por un denario: y no hagas daño al vino ni al aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 7, 'Y cuando él abrió el cuarto sello, oí la voz del cuarto animal, que decía: Ven y ve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 8, 'Y miré, y he aquí un caballo amarillo: y el que estaba sentado sobre él tenía por nombre Muerte; y el infierno le seguía: y le fué dada potestad sobre la cuarta parte de la tierra, para matar con espada, con hambre, con mortandad, y con las bestias de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 9, 'Y cuando él abrió el quinto sello, vi debajo del altar las almas de los que habían sido muertos por la palabra de Dios y por el testimonio que ellos tenían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 10, 'Y clamaban en alta voz diciendo: ¿Hasta cuándo, Señor, santo y verdadero, no juzgas y vengas nuestra sangre de los que moran en la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 11, 'Y les fueron dadas sendas ropas blancas, y fuéles dicho que reposasen todavía un poco de tiempo, hasta que se completaran sus consiervos y sus hermanos, que también habían de ser muertos como ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 12, 'Y miré cuando él abrió el sexto sello, y he aquí fué hecho un gran terremoto; y el sol se puso negro como un saco de cilicio, y la luna se puso toda como sangre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 13, 'Y las estrellas del cielo cayeron sobre la tierra, como la higuera echa sus higos cuando es movida de gran viento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 14, 'Y el cielo se apartó como un libro que es envuelto; y todo monte y las islas fueron movidas de sus lugares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 15, 'Y los reyes de la tierra, y los príncipes, y los ricos, y los capitanes, y los fuertes, y todo siervo y todo libre, se escondieron en las cuevas y entre las peñas de los montes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 16, 'Y decían á los montes y á las peñas: Caed sobre nosotros, y escondednos de la cara de aquél que está sentado sobre el trono, y de la ira del Cordero:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 6, 17, 'Porque el gran día de su ira es venido; ¿y quién podrá estar firme?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 1, 'Y DESPUÉS de estas cosas vi cuatro ángeles que estaban sobre los cuatro ángulos de la tierra, deteniendo los cuatro vientos de la tierra, para que no soplase viento sobre la tierra, ni sobre la mar, ni sobre ningún árbol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 2, 'Y vi otro ángel que subía del nacimiento del sol, teniendo el sello del Dios vivo: y clamó con gran voz á los cuatro ángeles, á los cuales era dado hacer daño á la tierra y á la mar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 3, 'Diciendo: No hagáis daño á la tierra, ni al mar, ni á los árboles, hasta que señalemos á los siervos de nuestro Dios en sus frentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 4, 'Y oí el número de los señalados: ciento cuarenta y cuatro mil señalados de todas las tribus de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 5, 'De la tribu de Judá, doce mil señalados. De la tribu de Rubén, doce mil señalados. De la tribu de Gad, doce mil señalados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 6, 'De la tribu de Aser, doce mil señalados. De la tribu de Neftalí, doce mil señalados. De la tribu de Manasés, doce mil señalados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 7, 'De la tribu de Simeón, doce mil señalados. De la tribu de Leví, doce mil señalados. De la tribu de Issachâr, doce mil señalados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 8, 'De la tribu de Zabulón, doce mil señalados. De la tribu de José, doce mil señalados. De la tribu de Benjamín, doce mil señalados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 9, 'Después de estas cosas miré, y he aquí una gran compañía, la cual ninguno podía contar, de todas gentes y linajes y pueblos y lenguas, que estaban delante del trono y en la presencia del Cordero, vestidos de ropas blancas, y palmas en sus manos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 10, 'Y clamaban en alta voz, diciendo: Salvación á nuestro Dios que está sentado sobre el trono, y al Cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 11, 'Y todos los ángeles estaban alrededor del trono, y de los ancianos y los cuatro animales; y postráronse sobre sus rostros delante del trono, y adoraron á Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 12, 'Diciendo: Amén: La bendición y la gloria y la sabiduría, y la acción de gracias y la honra y la potencia y la fortaleza, sean á nuestro Dios para siempre jamás. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 13, 'Y respondió uno de los ancianos, diciéndome: Estos que están vestidos de ropas blancas, ¿quiénes son, y de dónde han venido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 14, 'Y yo le dije: Señor, tú lo sabes. Y él me dijo: Estos son los que han venido de grande tribulación, y han lavado sus ropas, y las han blanqueado en la sangre del Cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 15, 'Por esto están delante del trono de Dios, y le sirven día y noche en su templo: y el que está sentado en el trono tenderá su pabellón sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 16, 'No tendrán más hambre, ni sed, y el sol no caerá más sobre ellos, ni otro ningún calor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 7, 17, 'Porque el Cordero que está en medio del trono los pastoreará, y los guiará á fuentes vivas de aguas: y Dios limpiará toda lágrima de los ojos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 1, 'Y CUANDO él abrió el séptimo sello, fué hecho silencio en el cielo casi por media hora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 2, 'Y vi los siete ángeles que estaban delante de Dios; y les fueron dadas siete trompetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 3, 'Y otro ángel vino, y se paró delante del altar, teniendo un incensario de oro; y le fué dado mucho incienso para que lo añadiese á las oraciones de todos los santos sobre el altar de oro que estaba delante del trono.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 4, 'Y el humo del incienso subió de la mano del ángel delante de Dios, con las oraciones de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 5, 'Y el ángel tomó el incensario, y lo llenó del fuego del altar, y echólo en la tierra; y fueron hechos truenos y voces y relámpagos y terremotos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 6, 'Y los siete ángeles que tenían las siete trompetas, se aparejaron para tocar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 7, 'Y el primer ángel tocó la trompeta, y fué hecho granizo y fuego, mezclado con sangre, y fueron arrojados á la tierra; y la tercera parte de los árboles fué quemada, y quemóse toda la hierba verde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 8, 'Y el segundo ángel tocó la trompeta, y como un grande monte ardiendo con fuego fué lanzado en la mar; y la tercera parte de la mar se tornó en sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 9, 'Y murió la tercera parte de las criaturas que estaban en la mar, las cuales tenían vida; y la tercera parte de los navíos pereció.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 10, 'Y el tercer ángel tocó la trompeta, y cayó del cielo una grande estrella, ardiendo como una antorcha, y cayó en la tercera parte de los rios, y en las fuentes de las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 11, 'Y el nombre de la estrella se dice Ajenjo. Y la tercera parte de las aguas fué vuelta en ajenjo: y muchos murieron por las aguas, porque fueron hechas amargas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 12, 'Y el cuarto ángel tocó la trompeta, y fué herida la tercera parte del sol, y la tercera parte de la luna, y la tercera parte de las estrellas; de tal manera que se oscureció la tercera parte de ellos, y no alumbraba la tercera parte del día, y lo mismo de la noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 8, 13, 'Y miré, y oí un ángel volar por medio del cielo, diciendo en alta voz: ¡Ay! ¡ay! ¡ay! de los que moran en la tierra, por razón de las otras voces de trompeta de los tres ángeles que han de tocar!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 1, 'Y EL quinto ángel tocó la trompeta, y vi una estrella que cayó del cielo en la tierra; y le fué dada la llave del pozo del abismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 2, 'Y abrió el pozo del abismo, y subió humo del pozo como el humo de un gran horno; y oscurecióse el sol y el aire por el humo del pozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 3, 'Y del humo salieron langostas sobre la tierra; y fueles dada potestad, como tienen potestad los escorpiones de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 4, 'Y les fué mandado que no hiciesen daño á la hierba de la tierra, ni á ninguna cosa verde, ni á ningún árbol, sino solamente á los hombres que no tienen la señal de Dios en sus frentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 5, 'Y le fué dado que no los matasen, sino que los atormentasen cinco meses; y su tormento era como tormento de escorpión, cuando hiere al hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 6, 'Y en aquellos días buscarán los hombres la muerte, y no la hallarán; y desearán morir, y la muerte huirá de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 7, 'Y el parecer de las langostas era semejante á caballos aparejados para la guerra: y sobre sus cabezas tenían como coronas semejantes al oro; y sus caras como caras de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 8, 'Y tenían cabellos como cabellos de mujeres: y sus dientes eran como dientes de leones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 9, 'Y tenían corazas como corazas de hierro; y el estruendo de sus alas, como el ruido de carros que con muchos caballos corren á la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 10, 'Y tenían colas semejantes á las de los escorpiones, y tenían en sus colas aguijones; y su poder era de hacer daño á los hombres cinco meses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 11, 'Y tienen sobre sí por rey al ángel del abismo, cuyo nombre en hebraico es Abaddon, y en griego, Apollyon.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 12, 'El primer ¡Ay! es pasado: he aquí, vienen aún dos ayes después de estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 13, 'Y el sexto ángel tocó la trompeta; y oí una voz de los cuatro cuernos del altar de oro que estaba delante de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 14, 'Diciendo al sexto ángel que tenía la trompeta: Desata los cuatro ángeles que están atados en el gran río Eufrates.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 15, 'Y fueron desatados los cuatro ángeles que estaban aparejados para la hora y día y mes y año, para matar la tercera parte de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 16, 'Y el número del ejército de los de á caballo era doscientos millones. Y oí el número de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 17, 'Y así vi los caballos en visión, y los que sobre ellos estaban sentados, los cuales tenían corazas de fuego, de jacinto, y de azufre. Y las cabezas de los caballos eran como cabezas de leones; y de la boca de ellos salía fuego y humo y azufre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 18, 'De estas tres plagas fué muerta la tercera parte de los hombres: del fuego, y del humo, y del azufre, que salían de la boca de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 19, 'Porque su poder está en su boca y en sus colas: porque sus colas eran semejantes á serpientes, y tenían cabezas, y con ellas dañan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 20, 'Y los otros hombres que no fueron muertos con estas plagas, aun no se arrepintieron de las obras de sus manos, para que no adorasen á los demonios, y á las imágenes de oro, y de plata, y de metal, y de piedra, y de madera; las cuales no pueden ver, ni oir, ni andar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 9, 21, 'Y no se arrepintieron de sus homicidios, ni de sus hechicerías, ni de su fornicación, ni de sus hurtos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 1, 'Y VI otro ángel fuerte descender del cielo, cercado de una nube, y el arco celeste sobre su cabeza; y su rostro era como el sol, y sus pies como columnas de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 2, 'Y tenía en su mano un librito abierto: y puso su pie derecho sobre el mar, y el izquierdo sobre la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 3, 'Y clamó con grande voz, como cuando un león ruge: y cuando hubo clamado, siete truenos hablaron sus voces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 4, 'Y cuando los siete truenos hubieron hablado sus voces, yo iba á escribir, y oí una voz del cielo que me decía: Sella las cosas que los siete truenos han hablado, y no las escribas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 5, 'Y el ángel que vi estar sobre el mar y sobre la tierra, levantó su mano al cielo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 6, 'Y juró por el que vive para siempre jamás, que ha criado el cielo y las cosas que están en él, y la tierra y las cosas que están en ella, y el mar y las cosas que están en él, que el tiempo no será más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 7, 'Pero en los días de la voz del séptimo ángel, cuando él comenzare á tocar la trompeta, el misterio de Dios será consumado, como él lo anunció á sus siervos los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 8, 'Y la voz que oí del cielo hablaba otra vez conmigo, y decía: Ve, y toma el librito abierto de la mano del ángel que está sobre el mar y sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 9, 'Y fuí al ángel, diciéndole que me diese el librito, y él me dijo: Toma, y trágalo; y él te hará amargar tu vientre, pero en tu boca será dulce como la miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 10, 'Y tomé el librito de la mano del ángel, y lo devoré; y era dulce en mi boca como la miel; y cuando lo hube devorado, fué amargo mi vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 10, 11, 'Y él me dice: Necesario es que otra vez profetices á muchos pueblos y gentes y lenguas y reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 1, 'Y ME fué dada una caña semejante á una vara, y se me dijo: Levántate, y mide el templo de Dios, y el altar, y á los que adoran en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 2, 'Y echa fuera el patio que está fuera del templo, y no lo midas, porque es dado á los Gentiles; y hollarán la ciudad santa cuarenta y dos meses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 3, 'Y daré á mis dos testigos, y ellos profetizarán por mil doscientos y sesenta días, vestidos de sacos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 4, 'Estas son las dos olivas, y los dos candeleros que están delante del Dios de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 5, 'Y si alguno les quisiere dañar, sale fuego de la boca de ellos, y devora á sus enemigos: y si alguno les quisiere hacer daño, es necesario que él sea así muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 6, 'Estos tienen potestad de cerrar el cielo, que no llueva en los días de su profecía, y tienen poder sobre las aguas para convertirlas en sangre, y para herir la tierra con toda plaga cuantas veces quisieren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 7, 'Y cuando ellos hubieren acabado su testimonio, la bestia que sube del abismo hará guerra contra ellos, y los vencerá, y los matará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 8, 'Y sus cuerpos serán echados en las plazas de la grande ciudad, que espiritualmente es llamada Sodoma y Egipto, donde también nuestro Señor fué crucificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 9, 'Y los de los linajes, y de los pueblos, y de las lenguas, y de los Gentiles verán los cuerpos de ellos por tres días y medio, y no permitirán que sus cuerpos sean puestos en sepulcros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 10, 'Y los moradores de la tierra se gozarán sobre ellos, y se alegrarán, y se enviarán dones los unos á los otros; porque estos dos profetas han atormentado á los que moran sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 11, 'Y después de tres días y medio el espíritu de vida enviado de Dios, entró en ellos, y se alzaron sobre sus pies, y vino gran temor sobre los que los vieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 12, 'Y oyeron una grande voz del cielo, que les decía: Subid acá. Y subieron al cielo en una nube, y sus enemigos los vieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 13, 'Y en aquella hora fué hecho gran temblor de tierra, y la décima parte de la ciudad cayó, y fueron muertos en el temblor de tierra en número de siete mil hombres: y los demás fueron espantados, y dieron gloria al Dios del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 14, 'El segundo ¡Ay! es pasado: he aquí, el tercer ¡Ay! vendrá presto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 15, 'Y el séptimo ángel tocó la trompeta, y fueron hechas grandes voces en el cielo, que decían: Los reinos del mundo han venido á ser los reinos de nuestro Señor, y de su Cristo: y reinará para siempre jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 16, 'Y los veinticuatro ancianos que estaban sentados delante de Dios en sus sillas, se postraron sobre sus rostros, y adoraron á Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 17, 'Diciendo: Te damos gracias, Señor Dios Todopoderoso, que eres y que eras y que has de venir, porque has tomado tu grande potencia, y has reinado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 18, 'Y se han airado las naciones, y tu ira es venida, y el tiempo de los muertos, para que sean juzgados, y para que des el galardón á tus siervos los profetas, y á los santos, y á los que temen tu nombre, á los pequeñitos y á los grandes, y para que destruyas los que destruyen la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 11, 19, 'Y el templo de Dios fué abierto en el cielo, y el arca de su testamento fué vista en su templo. Y fueron hechos relámpagos y voces y truenos y terremotos y grande granizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 1, 'Y UNA grande señal apareció en el cielo: una mujer vestida del sol, y la luna debajo de sus pies, y sobre su cabeza una corona de doce estrellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 2, 'Y estando preñada, clamaba con dolores de parto, y sufría tormento por parir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 3, 'Y fué vista otra señal en el cielo: y he aquí un grande dragón bermejo, que tenía siete cabezas y diez cuernos, y en sus cabezas siete diademas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 4, 'Y su cola arrastraba la tercera parte de las estrellas del cielo, y las echó en tierra. Y el dragón se paró delante de la mujer que estaba para parir, á fin de devorar á su hijo cuando hubiese parido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 5, 'Y ella parió un hijo varón, el cual había de regir todas las gentes con vara de hierro: y su hijo fué arrebatado para Dios y á su trono.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 6, 'Y la mujer huyó al desierto, donde tiene lugar aparejado de Dios, para que allí la mantengan mil doscientos y sesenta días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 7, 'Y fué hecha una grande batalla en el cielo: Miguel y sus ángeles lidiaban contra el dragón; y lidiaba el dragón y sus ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 8, 'Y no prevalecieron, ni su lugar fué más hallado en el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 9, 'Y fué lanzado fuera aquel gran dragón, la serpiente antigua, que se llama Diablo y Satanás, el cual engaña á todo el mundo; fué arrojado en tierra, y sus ángeles fueron arrojados con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 10, 'Y oí una grande voz en el cielo que decía: Ahora ha venido la salvación, y la virtud, y el reino de nuestro Dios, y el poder de su Cristo; porque el acusador de nuestros hermanos ha sido arrojado, el cual los acusaba delante de nuestro Dios día y noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 11, 'Y ellos le han vencido por la sangre del Cordero, y por la palabra de su testimonio; y no han amado sus vidas hasta la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 12, 'Por lo cual alegraos, cielos, y los que moráis en ellos. ¡Ay de los moradores de la tierra y del mar! porque el diablo ha descendido á vosotros, teniendo grande ira, sabiendo que tiene poco tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 13, 'Y cuando vió el dragón que él había sido arrojado á la tierra, persiguió á la mujer que había parido al hijo varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 14, 'Y fueron dadas á la mujer dos alas de grande águila, para que de la presencia de la serpiente volase al desierto, á su lugar, donde es mantenida por un tiempo, y tiempos, y la mitad de un tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 15, 'Y la serpiente echó de su boca tras la mujer agua como un río, á fin de hacer que fuese arrebatada del río.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 16, 'Y la tierra ayudó á la mujer, y la tierra abrió su boca, y sorbió el río que había echado el dragón de su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 12, 17, 'Entonces el dragón fué airado contra la mujer; y se fué á hacer guerra contra los otros de la simiente de ella, los cuales guardan los mandamientos de Dios, y tienen el testimonio de Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 1, 'Y YO me paré sobre la arena del mar, y vi una bestia subir del mar, que tenía siete cabezas y diez cuernos; y sobre sus cuernos diez diademas; y sobre las cabezas de ella nombre de blasfemia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 2, 'Y la bestia que vi, era semejante á un leopardo, y sus pies como de oso, y su boca como boca de león. Y el dragón le dió su poder, y su trono, y grande potestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 3, 'Y vi una de sus cabezas como herida de muerte, y la llaga de su muerte fué curada: y se maravilló toda la tierra en pos de la bestia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 4, 'Y adoraron al dragón que había dado la potestad á la bestia, y adoraron á la bestia, diciendo: ¿Quién es semejante á la bestia, y quién podrá lidiar con ella?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 5, 'Y le fué dada boca que hablaba grandes cosas y blasfemias: y le fué dada potencia de obrar cuarenta y dos meses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 6, 'Y abrió su boca en blasfemias contra Dios, para blasfemar su nombre, y su tabernáculo, y á los que moran en el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 7, 'Y le fué dado hacer guerra contra los santos, y vencerlos. También le fué dada potencia sobre toda tribu y pueblo y lengua y gente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 8, 'Y todos los que moran en la tierra le adoraron, cuyos nombres no están escritos en el libro de la vida del Cordero, el cual fué muerto desde el principio del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 9, 'Si alguno tiene oído, oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 10, 'El que lleva en cautividad, va en cautividad: el que á cuchillo matare, es necesario que á cuchillo sea muerto. Aquí está la paciencia y la fe de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 11, 'Después vi otra bestia que subía de la tierra; y tenía dos cuernos semejantes á los de un cordero, mas hablaba como un dragón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 12, 'Y ejerce todo el poder de la primera bestia en presencia de ella; y hace á la tierra y á los moradores de ella adorar la primera bestia, cuya llaga de muerte fué curada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 13, 'Y hace grandes señales, de tal manera que aun hace descender fuego del cielo á la tierra delante de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 14, 'Y engaña á los moradores de la tierra por las señales que le ha sido dado hacer en presencia de la bestia, mandando á los moradores de la tierra que hagan la imagen de la bestia que tiene la herida de cuchillo, y vivió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 15, 'Y le fué dado que diese espíritu á la imagen de la bestia, para que la imagen de la bestia hable; y hará que cualesquiera que no adoraren la imagen de la bestia sean muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 16, 'Y hacía que á todos, á los pequeños y grandes, ricos y pobres, libres y siervos, se pusiese una marca en su mano derecha, ó en sus frentes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 17, 'Y que ninguno pudiese comprar ó vender, sino el que tuviera la señal, ó el nombre de la bestia, ó el número de su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 13, 18, 'Aquí hay sabiduría. El que tiene entendimiento, cuente el número de la bestia; porque es el número de hombre: y el número de ella, seiscientos sesenta y seis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 1, 'Y MIRÉ, y he aquí, el Cordero estaba sobre el monte de Sión, y con él ciento cuarenta y cuatro mil, que tenían el nombre de su Padre escrito en sus frentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 2, 'Y oí una voz del cielo como ruido de muchas aguas, y como sonido de un gran trueno: y oí una voz de tañedores de arpas que tañían con sus arpas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 3, 'Y cantaban como un cántico nuevo delante del trono, y delante de los cuatro animales, y de los ancianos: y ninguno podía aprender el cántico sino aquellos ciento cuarenta y cuatro mil, los cuales fueron comprados de entre los de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 4, 'Estos son los que con mujeres no fueron contaminados; porque son vírgenes. Estos, los que siguen al Cordero por donde quiera que fuere. Estos fueron comprados de entre los hombres por primicias para Dios y para el Cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 5, 'Y en sus bocas no ha sido hallado engaño; porque ellos son sin mácula delante del trono de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 6, 'Y vi otro ángel volar por en medio del cielo, que tenía el evangelio eterno para predicarlo á los que moran en la tierra, y á toda nación y tribu y lengua y pueblo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 7, 'Diciendo en alta voz: Temed á Dios, y dadle honra; porque la hora de su juicio es venida; y adorad á aquel que ha hecho el cielo y la tierra y el mar y las fuentes de las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 8, 'Y otro ángel le siguió, diciendo: Ha caído, ha caído Babilonia, aquella grande ciudad, porque ella ha dado á beber á todas las naciones del vino del furor de su fornicación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 9, 'Y el tercer ángel los siguió, diciendo en alta voz: Si alguno adora á la bestia y á su imagen, y toma la señal en su frente, ó en su mano,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 10, 'Este también beberá del vino de la ira de Dios, el cual está echado puro en el cáliz de su ira; y será atormentado con fuego y azufre delante de los santos ángeles, y delante del Cordero:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 11, 'Y el humo del tormento de ellos sube para siempre jamás. Y los que adoran á la bestia y á su imagen, no tienen reposo día ni noche, ni cualquiera que tomare la señal de su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 12, 'Aquí está la paciencia de los santos; aquí están los que guardan los mandamientos de Dios, y la fe de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 13, 'Y oí una voz del cielo que me decía: Escribe: Bienaventurados los muertos que de aquí adelante mueren en el Señor. Sí, dice el Espíritu, que descansarán de sus trabajos; porque sus obras con ellos siguen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 14, 'Y miré, y he aquí una nube blanca; y sobre la nube uno sentado semejante al Hijo del hombre, que tenía en su cabeza una corona de oro, y en su mano una hoz aguda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 15, 'Y otro ángel salió del templo, clamando en alta voz al que estaba sentado sobre la nube: Mete tu hoz, y siega; porque la hora de segar te es venida, porque la mies de la tierra está madura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 16, 'Y el que estaba sentado sobre la nube echó su hoz sobre la tierra, y la tierra fué segada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 17, 'Y salió otro ángel del templo que está en el cielo, teniendo también una hoz aguda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 18, 'Y otro ángel salió del altar, el cual tenía poder sobre el fuego, y clamó con gran voz al que tenía la hoz aguda, diciendo: Mete tu hoz aguda, y vendimia los racimos de la tierra; porque están maduras sus uvas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 19, 'Y el ángel echó su hoz aguda en la tierra, y vendimió la viña de la tierra, y echó la uva en el grande lagar de la ira de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 14, 20, 'Y el lagar fué hollado fuera de la ciudad, y del lagar salió sangre hasta los frenos de los caballos por mil y seiscientos estadios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 15, 1, 'Y VI otra señal en el cielo, grande y admirable, que era siete ángeles que tenían las siete plagas postreras; porque en ellas es consumada la ira de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 15, 2, 'Y vi así como un mar de vidrio mezclado con fuego; y los que habían alcanzado la victoria de la bestia, y de su imagen, y de su señal, y del número de su nombre, estar sobre el mar de vidrio, teniendo las arpas de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 15, 3, 'Y cantan el cántico de Moisés siervo de Dios, y el cántico del Cordero, diciendo: Grandes y maravillosas son tus obras, Señor Dios Todopoderoso; justos y verdaderos son tus caminos, Rey de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 15, 4, '¿Quién no te temerá, oh Señor, y engrandecerá tu nombre? porque tú sólo eres santo; por lo cual todas las naciones vendrán, y adorarán delante de ti, porque tus juicios son manifestados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 15, 5, 'Y después de estas cosas miré, y he aquí el templo del tabernáculo del testimonio fué abierto en el cielo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 15, 6, 'Y salieron del templo siete ángeles, que tenían siete plagas, vestidos de un lino limpio y blanco, y ceñidos alrededor de los pechos con bandas de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 15, 7, 'Y uno de los cuatro animales dió á los siete ángeles siete copas de oro, llenas de la ira de Dios, que vive para siempre jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 15, 8, 'Y fué el templo lleno de humo por la majestad de Dios, y por su potencia; y ninguno podía entrar en el templo, hasta que fuesen consumadas las siete plagas de los siete ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 1, 'Y OI una gran voz del templo, que decía á los siete ángeles: Id, y derramad las siete copas de la ira de Dios sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 2, 'Y fué el primero, y derramó su copa sobre la tierra; y vino una plaga mala y dañosa sobre los hombres que tenían la señal de la bestia, y sobre los que adoraban su imagen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 3, 'Y el segundo ángel derramó su copa sobre el mar, y se convirtió en sangre como de un muerto; y toda alma viviente fué muerta en el mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 4, 'Y el tercer ángel derramó su copa sobre los ríos, y sobre las fuentes de las aguas, y se convirtieron en sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 5, 'Y oí al ángel de las aguas, que decía: Justo eres tú, oh Señor, que eres y que eras, el Santo, porque has juzgado estas cosas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 6, 'Porque ellos derramaron la sangre de los santos y de los profetas, también tú les has dado á beber sangre; pues lo merecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 7, 'Y oí á otro del altar, que decía: Ciertamente, Señor Dios Todopoderoso, tus juicios son verdaderos y justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 8, 'Y el cuarto ángel derramó su copa sobre el sol; y le fué dado quemar á los hombres con fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 9, 'Y los hombres se quemaron con el grande calor, y blasfemaron el nombre de Dios, que tiene potestad sobre estas plagas, y no se arrepintieron para darle gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 10, 'Y el quinto ángel derramó su copa sobre la silla de la bestia; y su reino se hizo tenebroso, y se mordían sus lenguas de dolor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 11, 'Y blasfemaron del Dios del cielo por sus dolores, y por sus plagas, y no se arrepintieron de sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 12, 'Y el sexto ángel derramó su copa sobre el gran río Eufrates; y el agua de él se secó, para que fuese preparado el camino de los reyes del Oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 13, 'Y vi salir de la boca del dragón, y de la boca de la bestia, y de la boca del falso profeta, tres espíritus inmundos á manera de ranas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 14, 'Porque son espíritus de demonios, que hacen señales, para ir á los reyes de la tierra y de todo el mundo, para congregarlos para la batalla de aquel gran día del Dios Todopoderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 15, 'He aquí, yo vengo como ladrón. Bienaventurado el que vela, y guarda sus vestiduras, para que no ande desnudo, y vean su vergüenza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 16, 'Y los congregó en el lugar que en hebreo se llama Armagedón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 17, 'Y el séptimo ángel derramó su copa por el aire; y salió una grande voz del templo del cielo, del trono, diciendo: Hecho es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 18, 'Entonces fueron hechos relámpagos y voces y truenos; y hubo un gran temblor de tierra, un terremoto tan grande, cual no fué jamás desde que los hombres han estado sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 19, 'Y la ciudad grande fué partida en tres partes, y las ciudades de las naciones cayeron; y la grande Babilonia vino en memoria delante de Dios, para darle el cáliz del vino del furor de su ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 20, 'Y toda isla huyó, y los montes no fueron hallados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 16, 21, 'Y cayó del cielo sobre los hombres un grande granizo como del peso de un talento: y los hombres blasfemaron de Dios por la plaga del granizo; porque su plaga fué muy grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 1, 'Y VINO uno de los siete ángeles que tenían las siete copas, y habló conmigo, diciéndome: Ven acá, y te mostraré la condenación de la grande ramera, la cual está sentada sobre muchas aguas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 2, 'Con la cual han fornicado los reyes de la tierra, y los que moran en la tierra se han embriagado con el vino de su fornicación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 3, 'Y me llevó en Espíritu al desierto; y vi una mujer sentada sobre una bestia bermeja llena de nombres de blasfemia y que tenía siete cabezas y diez cuernos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 4, 'Y la mujer estaba vestida de púrpura y de escarlata, y dorada con oro, y adornada de piedras preciosas y de perlas, teniendo un cáliz de oro en su mano lleno de abominaciones y de la suciedad de su fornicación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 5, 'Y en su frente un nombre escrito: MISTERIO, BABILONIA LA GRANDE, LA MADRE DE LAS FORNICACIONES Y DE LAS ABOMINACIONES DE LA TIERRA.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 6, 'Y vi la mujer embriagada de la sangre de los santos, y de la sangre de los mártires de Jesús: y cuando la vi, quedé maravillado de grande admiración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 7, 'Y el ángel me dijo: ¿Por qué te maravillas? Yo te diré el misterio de la mujer, y de la bestia que la trae, la cual tiene siete cabezas y diez cuernos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 8, 'La bestia que has visto, fué, y no es; y ha de subir del abismo, y ha de ir á perdición: y los moradores de la tierra, cuyos nombres no están escritos en el libro de la vida desde la fundación del mundo, se maravillarán viendo la bestia que era y no es, aunque es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 9, 'Y aquí hay mente que tiene sabiduría. Las siete cabezas son siete montes, sobre los cuales se asienta la mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 10, 'Y son siete reyes. Los cinco son caídos; el uno es, el otro aun no es venido; y cuando viniere, es necesario que dure breve tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 11, 'Y la bestia que era, y no es, es también el octavo, y es de los siete, y va á perdición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 12, 'Y los diez cuernos que has visto, son diez reyes, que aun no han recibido reino; mas tomarán potencia por una hora como reyes con la bestia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 13, 'Estos tienen un consejo, y darán su potencia y autoridad á la bestia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 14, 'Ellos pelearán contra el Cordero, y el Cordero los vencerá, porque es el Señor de los señores, y el Rey de los reyes: y los que están con él son llamados, y elegidos, y fieles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 15, 'Y él me dice: Las aguas que has visto donde la ramera se sienta, son pueblos y muchedumbres y naciones y lenguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 16, 'Y los diez cuernos que viste en la bestia, éstos aborrecerán á la ramera, y la harán desolada y desnuda: y comerán sus carnes, y la quemarán con fuego:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 17, 'Porque Dios ha puesto en sus corazones ejecutar lo que le plugo, y el ponerse de acuerdo, y dar su reino á la bestia, hasta que sean cumplidas las palabras de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 17, 18, 'Y la mujer que has visto, es la grande ciudad que tiene reino sobre los reyes de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 1, 'Y DESPUÉS de estas cosas vi otro ángel descender del cielo teniendo grande potencia; y la tierra fué alumbrada de su gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 2, 'Y clamó con fortaleza en alta voz, diciendo: Caída es, caída es la grande Babilonia, y es hecha habitación de demonios, y guarida de todo espíritu inmundo, y albergue de todas aves sucias y aborrecibles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 3, 'Porque todas las gentes han bebido del vino del furor de su fornicación; y los reyes de la tierra han fornicado con ella, y los mercaderes de la tierra se han enriquecido de la potencia de sus deleites.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 4, 'Y oí otra voz del cielo, que decía: Salid de ella, pueblo mío, porque no seáis participantes de sus pecados, y que no recibáis de sus plagas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 5, 'Porque sus pecados han llegado hasta el cielo, y Dios se ha acordado de sus maldades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 6, 'Tornadle á dar como ella os ha dado, y pagadle al doble según sus obras; en el cáliz que ella os dió á beber, dadle á beber doblado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 7, 'Cuanto ella se ha glorificado, y ha estado en deleites, tanto dadle de tormento y llanto; porque dice en su corazón: Yo estoy sentada reina, y no soy viuda, y no veré llanto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 8, 'Por lo cual en un día vendrán sus plagas, muerte, llanto y hambre, y será quemada con fuego; porque el Señor Dios es fuerte, que la juzgará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 9, 'Y llorarán y se lamentarán sobre ella los reyes de la tierra, los cuales han fornicado con ella y han vivido en deleites, cuando ellos vieren el humo de su incendio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 10, 'Estando lejos por el temor de su tormento, diciendo: ¡Ay, ay, de aquella gran ciudad de Babilonia, aquella fuerte ciudad; porque en una hora vino tu juicio!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 11, 'Y los mercaderes de la tierra lloran y se lamentan sobre ella, porque ninguno compra más sus mercaderías:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 12, 'Mercadería de oro, y de plata, y de piedras preciosas, y de margaritas, y de lino fino, y de escarlata, y de seda, y de grana, y de toda madera olorosa, y de todo vaso de marfil, y de todo vaso de madera preciosa, y de cobre, y de hierro, y de mármol;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 13, 'Y canela, y olores, y ungüentos, y de incienso, y de vino, y de aceite; y flor de harina y trigo, y de bestias, y de ovejas; y de caballos, y de carros, y de siervos, y de almas de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 14, 'Y los frutos del deseo de tu alma se apartaron de ti; y todas las cosas gruesas y excelentes te han faltado, y nunca más las hallarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 15, 'Los mercaderes de estas cosas, que se han enriquecido, se pondrán lejos de ella por el temor de su tormento, llorando y lamentando,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 16, 'Y diciendo: ¡Ay, ay, aquella gran ciudad, que estaba vestida de lino fino, y de escarlata, y de grana, y estaba dorada con oro, y adornada de piedras preciosas y de perlas!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 17, 'Porque en una hora han sido desoladas tantas riquezas. Y todo patrón, y todos los que viajan en naves, y marineros, y todos los que trabajan en el mar, se estuvieron lejos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 18, 'Y viendo el humo de su incendio, dieron voces, diciendo: ¿Qué ciudad era semejante á esta gran ciudad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 19, 'Y echaron polvo sobre sus cabezas; y dieron voces, llorando y lamentando, diciendo: ¡Ay, ay, de aquella gran ciudad, en la cual todos los que tenían navíos en la mar se habían enriquecido de sus riquezas; que en una hora ha sido desolada!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 20, 'Alégrate sobre ella, cielo, y vosotros, santos, apóstoles, y profetas; porque Dios ha vengado vuestra causa en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 21, 'Y un ángel fuerte tomó una piedra como una grande piedra de molino, y la echó en la mar, diciendo: Con tanto ímpetu será derribada Babilonia, aquella grande ciudad, y nunca jamás será hallada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 22, 'Y voz de tañedores de arpas, y de músicos, y de tañedores de flautas y de trompetas, no será más oída en ti; y todo artífice de cualquier oficio, no será más hallado en ti; y el sonido de muela no será más en ti oído:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 23, 'Y luz de antorcha no alumbrará más en ti; y voz de esposo ni de esposa no será más en ti oída; porque tus mercaderes eran los magnates de la tierra; porque en tus hechicerías todas las gentes han errado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 18, 24, 'Y en ella fué hallada la sangre de los profetas y de los santos, y de todos los que han sido muertos en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 1, 'DESPUÉS de estas cosas oí una gran voz de gran compañía en el cielo, que decía: Aleluya: Salvación y honra y gloria y potencia al Señor Dios nuestro');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 2, 'Porque sus juicios son verdaderos y justos; porque él ha juzgado á la grande ramera, que ha corrompido la tierra con su fornicación, y ha vengado la sangre de sus siervos de la mano de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 3, 'Y otra vez dijeron: Aleluya. Y su humo subió para siempre jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 4, 'Y los veinticuatro ancianos y los cuatro animales se postraron en tierra, y adoraron á Dios que estaba sentado sobre el trono, diciendo: Amén: Aleluya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 5, 'Y salió una voz del trono, que decía: Load á nuestro Dios todos sus siervos, y los que le teméis, así pequeños como grandes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 6, 'Y oí como la voz de una grande compañía, y como el ruido de muchas aguas, y como la voz de grandes truenos, que decía: Aleluya: porque reinó el Señor nuestro Dios Todopoderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 7, 'Gocémonos y alegrémonos y démosle gloria; porque son venidas las bodas del Cordero, y su esposa se ha aparejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 8, 'Y le fué dado que se vista de lino fino, limpio y brillante: porque el lino fino son las justificaciones de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 9, 'Y él me dice: Escribe: Bienaventurados los que son llamados á la cena del Cordero. Y me dijo: Estas palabras de Dios son verdaderas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 10, 'Y yo me eché á sus pies para adorarle. Y él me dijo: Mira que no lo hagas: yo soy siervo contigo, y con tus hermanos que tienen el testimonio de Jesús: adora á Dios; porque el testimonio de Jesús es el espíritu de la profecía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 11, 'Y vi el cielo abierto; y he aquí un caballo blanco, y el que estaba sentado sobre él, era llamado Fiel y Verdadero, el cual con justicia juzga y pelea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 12, 'Y sus ojos eran como llama de fuego, y había en su cabeza muchas diademas; y tenía un nombre escrito que ninguno entendía sino él mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 13, 'Y estaba vestido de una ropa teñida en sangre: y su nombre es llamado EL VERBO DE DIOS.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 14, 'Y los ejércitos que están en el cielo le seguían en caballos blancos, vestidos de lino finísimo, blanco y limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 15, 'Y de su boca sale una espada aguda, para herir con ella las gentes: y él los regirá con vara de hierro; y él pisa el lagar del vino del furor, y de la ira del Dios Todopoderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 16, 'Y en su vestidura y en su muslo tiene escrito este nombre: REY DE REYES Y SEñOR DE SEñORES.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 17, 'Y vi un ángel que estaba en el sol, y clamó con gran voz, diciendo á todas las aves que volaban por medio del cielo: Venid, y congregaos á la cena del gran Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 18, 'Para que comáis carnes de reyes, y de capitanes, y carnes de fuertes, y carnes de caballos, y de los que están sentados sobre ellos; y carnes de todos, libres y siervos, de pequeños y de grandes');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 19, 'Y vi la bestia, y los reyes de la tierra y sus ejércitos, congregados para hacer guerra contra el que estaba sentado sobre el caballo, y contra su ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 20, 'Y la bestia fué presa, y con ella el falso profeta que había hecho las señales delante de ella, con las cuales había engañado á los que tomaron la señal de la bestia, y habían adorado su imagen. Estos dos fueron lanzados vivos dentro de un lago de fuego ardiendo en azufre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 19, 21, 'Y los otros fueron muertos con la espada que salía de la boca del que estaba sentado sobre el caballo, y todas las aves fueron hartas de las carnes de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 1, 'Y VI un ángel descender del cielo, que tenía la llave del abismo, y una grande cadena en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 2, 'Y prendió al dragón, aquella serpiente antigua, que es el Diablo y Satanás, y le ató por mil años;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 3, 'Y arrojólo al abismo, y le encerró, y selló sobre él, porque no engañe más á las naciones, hasta que mil años sean cumplidos: y después de esto es necesario que sea desatado un poco de tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 4, 'Y vi tronos, y se sentaron sobre ellos, y les fué dado juicio; y vi las almas de los degollados por el testimonio de Jesús, y por la palabra de Dios, y que no habían adorado la bestia, ni á su imagen, y que no recibieron la señal en sus frentes, ni en sus manos, y vivieron y reinaron con Cristo mil años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 5, 'Mas los otros muertos no tornaron á vivir hasta que sean cumplidos mil años. Esta es la primera resurrección.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 6, 'Bienaventurado y santo el que tiene parte en la primera resurrección; la segunda muerte no tiene potestad en éstos; antes serán sacerdotes de Dios y de Cristo, y reinarán con él mil años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 7, 'Y cuando los mil años fueren cumplidos, Satanás será suelto de su prisión,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 8, 'Y saldrá para engañar las naciones que están sobre los cuatro ángulos de la tierra, á Gog y á Magog, á fin de congregarlos para la batalla; el número de los cuales es como la arena del mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 9, 'Y subieron sobre la anchura de la tierra, y circundaron el campo de los santos, y la ciudad amada: y de Dios descendió fuego del cielo, y los devoró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 10, 'Y el diablo que los engañaba, fué lanzado en el lago de fuego y azufre, donde está la bestia y el falso profeta; y serán atormentados día y noche para siempre jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 11, 'Y vi un gran trono blanco y al que estaba sentado sobre él, de delante del cual huyó la tierra y el cielo; y no fué hallado el lugar de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 12, 'Y vi los muertos, grandes y pequeños, que estaban delante de Dios; y los libros fueron abiertos: y otro libro fué abierto, el cual es de la vida: y fueron juzgados los muertos por las cosas que estaban escritas en los libros, según sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 13, 'Y el mar dió los muertos que estaban en él; y la muerte y el infierno dieron los muertos que estaban en ellos; y fué hecho juicio de cada uno según sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 14, 'Y el infierno y la muerte fueron lanzados en el lago de fuego. Esta es la muerte segunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 20, 15, 'Y el que no fué hallado escrito en el libro de la vida, fué lanzado en el lago de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 1, 'Y VI un cielo nuevo, y una tierra nueva: porque el primer cielo y la primera tierra se fueron, y el mar ya no es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 2, 'Y yo Juan vi la santa ciudad, Jerusalem nueva, que descendía del cielo, de Dios, dispuesta como una esposa ataviada para su marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 3, 'Y oí una gran voz del cielo que decía: He aquí el tabernáculo de Dios con los hombres, y morará con ellos; y ellos serán su pueblo, y el mismo Dios será su Dios con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 4, 'Y limpiará Dios toda lágrima de los ojos de ellos; y la muerte no será más; y no habrá más llanto, ni clamor, ni dolor: porque las primeras cosas son pasadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 5, 'Y el que estaba sentado en el trono dijo: He aquí, yo hago nuevas todas las cosas. Y me dijo: Escribe; porque estas palabras son fieles y verdaderas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 6, 'Y díjome: Hecho es. Yo soy Alpha y Omega, el principio y el fin. Al que tuviere sed, yo le daré de la fuente del agua de vida gratuitamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 7, 'El que venciere, poseerá todas las cosas; y yo seré su Dios, y él será mi hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 8, 'Mas á los temerosos é incrédulos, á los abominables y homicidas, á los fornicarios y hechiceros, y á los idólatras, y á todos los mentirosos, su parte será en el lago ardiendo con fuego y azufre, que es la muerte segunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 9, 'Y vino á mí uno de los siete ángeles que tenían las siete copas llenas de las siete postreras plagas, y habló conmigo, diciendo: Ven acá, yo te mostraré la esposa, mujer del Cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 10, 'Y llevóme en Espíritu á un grande y alto monte, y me mostró la grande ciudad santa de Jerusalem, que descendía del cielo de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 11, 'Teniendo la claridad de Dios: y su luz era semejante á una piedra preciosísima, como piedra de jaspe, resplandeciente como cristal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 12, 'Y tenía un muro grande y alto con doce puertas; y en las puertas, doce ángeles, y nombres escritos, que son los de las doce tribus de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 13, 'Al oriente tres puertas; al norte tres puertas; al mediodiá tres puertas; al poniente tres puertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 14, 'Y el muro de la ciudad tenía doce fundamentos, y en ellos los doce nombres de los doce apóstoles del Cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 15, 'Y el que hablaba conmigo, tenía una medida de una caña de oro para medir la ciudad, y sus puertas, y su muro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 16, 'Y la ciudad está situada y puesta en cuadro, y su largura es tanta como su anchura: y él midió la ciudad con la caña, doce mil estadios: la largura y la altura y la anchura de ella son iguales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 17, 'Y midió su muro, ciento cuarenta y cuatro codos, de medida de hombre, la cual es del ángel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 18, 'Y el material de su muro era de jaspe: mas la ciudad era de oro puro, semejante al vidrio limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 19, 'Y los fundamentos del muro de la ciudad estaban adornados de toda piedra preciosa. El primer fundamento era jaspe; el segundo, zafiro; el tercero, calcedonia; el cuarto, esmeralda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 20, 'El quinto, sardónica; el sexto, sardio; el séptimo, crisólito; el octavo, berilo; el nono, topacio; el décimo, crisopraso; el undécimo, jacinto; el duodécimo, amatista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 21, 'Y las doce puertas eran doce perlas, en cada una, una; cada puerta era de una perla. Y la plaza de la ciudad era de oro puro como vidrio trasparente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 22, 'Y no vi en ella templo; porque el Señor Dios Todopoderoso es el templo de ella, y el Cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 23, 'Y la ciudad no tenía necesidad de sol, ni de luna, para que resplandezcan en ella: porque la claridad de Dios la iluminó, y el Cordero era su lumbrera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 24, 'Y las naciones que hubieren sido salvas andarán en la lumbre de ella: y los reyes de la tierra traerán su gloria y honor á ella');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 25, 'Y sus puertas nunca serán cerradas de día, porque allí no habrá noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 26, 'Y llevarán la gloria y la honra de las naciones á ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 21, 27, 'No entrará en ella ninguna cosa sucia, ó que hace abominación y mentira; sino solamente los que están escritos en el libro de la vida del Cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 1, 'DESPUÉS me mostró un río limpio de agua de vida, resplandeciente como cristal, que salía del trono de Dios y del Cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 2, 'En el medio de la plaza de ella, y de la una y de la otra parte del río, estaba el árbol de la vida, que lleva doce frutos, dando cada mes su fruto: y las hojas del árbol eran para la sanidad de las naciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 3, 'Y no habrá más maldición; sino que el trono de Dios y del Cordero estará en ella, y sus siervos le servirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 4, 'Y verán su cara; y su nombre estará en sus frentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 5, 'Y allí no habrá más noche; y no tienen necesidad de lumbre de antorcha, ni de lumbre de sol: porque el Señor Dios los alumbrará: y reinarán para siempre jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 6, 'Y me dijo: Estas palabras son fieles y verdaderas. Y el Señor Dios de los santos profetas ha enviado su ángel, para mostrar á sus siervos las cosas que es necesario que sean hechas presto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 7, 'Y he aquí, vengo presto. Bienaventurado el que guarda las palabras de la profecía de este libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 8, 'Yo Juan soy el que ha oído y visto estas cosas. Y después que hube oído y visto, me postré para adorar delante de los pies del ángel que me mostraba estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 9, 'Y él me dijo: Mira que no lo hagas: porque yo soy siervo contigo, y con tus hermanos los profetas, y con los que guardan las palabras de este libro. Adora á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 10, 'Y me dijo: No selles las palabras de la profecía de este libro; porque el tiempo está cerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 11, 'El que es injusto, sea injusto todavía: y el que es sucio, ensúciese todavía: y el que es justo, sea todavía justificado: y el santo sea santificado todavía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 12, 'Y he aquí, yo vengo presto, y mi galardón conmigo, para recompensar á cada uno según fuere su obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 13, 'Yo soy Alpha y Omega, principio y fin, el primero y el postrero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 14, 'Bienaventurados los que guardan sus mandamientos, para que su potencia sea en el árbol de la vida, y que entren por las puertas en la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 15, 'Mas los perros estarán fuera, y los hechiceros, y los disolutos, y los homicidas, y los idólatras, y cualquiera que ama y hace mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 16, 'Yo Jesús he enviado mi ángel para daros testimonio de estas cosas en las iglesias. Yo soy la raíz y el linaje de David, la estrella resplandeciente, y de la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 17, 'Y el Espíritu y la Esposa dicen: Ven. Y el que oye, diga: Ven. Y el que tiene sed, venga: y el que quiere, tome del agua de la vida de balde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 18, 'Porque yo protesto á cualquiera que oye las palabras de la profecía de este libro: Si alguno añadiere á estas cosas, Dios pondrá sobre él las plagas que están escritas en este libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 19, 'Y si alguno quitare de las palabras del libro de esta profecía, Dios quitará su parte del libro de la vida, y de la santa ciudad, y de las cosas que están escritas en este libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 20, 'El que da testimonio de estas cosas, dice: Ciertamente, vengo en breve. Amén, sea así. Ven: Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('REV', 'Apocalipsis', 22, 21, 'La gracia de nuestro Señor Jesucristo sea con todos vosotros. Amén.');
